window.searchIndexApi = [{"id":"api_decode","name":"base64\/decode","signatures":["(decode s & [strict?])"],"desc":"Decodes a Base64 string. Optional `strict?` flag validates characters.","anchor":"base64-decode","type":"api","kind":"function"},{"id":"api_decode-url","name":"base64\/decode-url","signatures":["(decode-url s & [strict?])"],"desc":"Decodes a URL-safe Base64 string. Adds padding automatically.","anchor":"base64-decode-url","type":"api","kind":"function"},{"id":"api_encode","name":"base64\/encode","signatures":["(encode s)"],"desc":"Encodes a string to Base64.","anchor":"base64-encode","type":"api","kind":"function"},{"id":"api_encode-url","name":"base64\/encode-url","signatures":["(encode-url s)"],"desc":"Encodes a string to URL-safe Base64 (no padding).","anchor":"base64-encode-url","type":"api","kind":"function"},{"id":"api_%","name":"%","signatures":["(% dividend divisor)"],"desc":"Return the remainder of `dividend` \/ `divisor`.","anchor":"","type":"api","kind":"function"},{"id":"api_*","name":"*","signatures":["(* & xs)"],"desc":"Returns the product of all elements in `xs`. All elements in `xs` must be\nnumbers. If `xs` is empty, return 1.","anchor":"-1","type":"api","kind":"function"},{"id":"api_**","name":"**","signatures":["(** a x)"],"desc":"Return `a` to the power of `x`.","anchor":"-2","type":"api","kind":"function"},{"id":"api_*assert*","name":"*assert*","signatures":[],"desc":"Controls whether `assert` expands to a runtime check. When logical\n  false at macroexpansion time, `assert` expands to nil and performs no\n  runtime check, matching Clojure's compile-time `*assert*` semantics.\n  Defaults to `true`. To disable globally, set the core binding before\n  compilation via PHP: `\\Phel::addDefinition(\"phel\\\\core\", \"*assert*\", false)`.","anchor":"assert","type":"api","kind":"function"},{"id":"api_*build-mode*","name":"*build-mode*","signatures":[],"desc":"Set to true when a file is being built\/compiled, false otherwise.","anchor":"build-mode","type":"api","kind":"function"},{"id":"api_*file*","name":"*file*","signatures":["*file*"],"desc":"Returns the path of the current source file.","anchor":"file","type":"api","kind":"function"},{"id":"api_*hierarchy*","name":"*hierarchy*","signatures":[],"desc":"Global hierarchy for keyword\/symbol taxonomies.","anchor":"hierarchy","type":"api","kind":"function"},{"id":"api_*ns*","name":"*ns*","signatures":["*ns*"],"desc":"Returns the namespace in the current scope.","anchor":"ns","type":"api","kind":"function"},{"id":"api_*program*","name":"*program*","signatures":[],"desc":"The script path or namespace being executed.","anchor":"program","type":"api","kind":"function"},{"id":"api_+","name":"+","signatures":["(+ & xs)"],"desc":"Returns the sum of all elements in `xs`. All elements `xs` must be numbers.\n  If `xs` is empty, return 0.","anchor":"-3","type":"api","kind":"function"},{"id":"api_-","name":"-","signatures":["(- & xs)"],"desc":"Returns the difference of all elements in `xs`. If `xs` is empty, return 0. If `xs`\n  has one element, return the negative value of that element.","anchor":"-4","type":"api","kind":"function"},{"id":"api_->","name":"->","signatures":["(-> x & forms)"],"desc":"Threads the expr through the forms. Inserts `x` as the second item\n  in the first form, making a list of it if it is not a list already.\n  If there are more forms, insert the first form as the second item in\n  the second form, etc.","anchor":"-5","type":"api","kind":"macro"},{"id":"api_->>","name":"->>","signatures":["(->> x & forms)"],"desc":"Threads the expr through the forms. Inserts `x` as the\n  last item in the first form, making a list of it if it is not a\n  list already. If there are more forms, insert the first form as the\n  last item in the second form, etc.","anchor":"-6","type":"api","kind":"macro"},{"id":"api_\/","name":"\/","signatures":["(\/ & xs)"],"desc":"Returns the nominator divided by all the denominators. If `xs` is empty,\nreturns 1. If `xs` has one value, returns the reciprocal of x.","anchor":"-7","type":"api","kind":"function"},{"id":"api_<","name":"<","signatures":["(< a & more)"],"desc":"Checks if each argument is strictly less than the following argument.","anchor":"-8","type":"api","kind":"function"},{"id":"api_<=","name":"<=","signatures":["(<= a & more)"],"desc":"Checks if each argument is less than or equal to the following argument. Returns a boolean.","anchor":"-9","type":"api","kind":"function"},{"id":"api_<=>","name":"<=>","signatures":["(<=> a b)"],"desc":"Alias for the spaceship PHP operator in ascending order. Returns an int.","anchor":"-10","type":"api","kind":"function"},{"id":"api_=","name":"=","signatures":["(= a & more)"],"desc":"Checks if all values are equal (value equality, not identity).","anchor":"-11","type":"api","kind":"function"},{"id":"api_>","name":">","signatures":["(> a & more)"],"desc":"Checks if each argument is strictly greater than the following argument.","anchor":"-12","type":"api","kind":"function"},{"id":"api_>=","name":">=","signatures":["(>= a & more)"],"desc":"Checks if each argument is greater than or equal to the following argument. Returns a boolean.","anchor":"-13","type":"api","kind":"function"},{"id":"api_>=<","name":">=<","signatures":["(>=< a b)"],"desc":"Alias for the spaceship PHP operator in descending order. Returns an int.","anchor":"-14","type":"api","kind":"function"},{"id":"api_NAN","name":"NAN","signatures":[],"desc":"Constant for Not a Number (NAN) values.","anchor":"nan","type":"api","kind":"function"},{"id":"api_NaN?","name":"NaN?","signatures":["(NaN? x)"],"desc":"Checks if `x` is not a number. Alias for `nan?`, matching Clojure's `NaN?`.","anchor":"NaN-1","type":"api","kind":"function"},{"id":"api_abs","name":"abs","signatures":["(abs x)"],"desc":"Returns the absolute value of `x`.\n  Throws `InvalidArgumentException` if `x` is not a number, matching Clojure\n  rather than PHP's permissive `abs(null) => 0` \/ `abs(\"abc\")` coercions.","anchor":"abs","type":"api","kind":"function"},{"id":"api_aclone","name":"aclone","signatures":["(aclone arr)"],"desc":"Returns a shallow copy of a PHP array. The returned array is a\n  distinct value \u2014 mutating the copy via `php\/aset` does not affect the\n  original, and vice versa. Matches Clojure's `aclone` for `.cljc`\n  interop; raises `InvalidArgumentException` on non-array inputs since\n  Phel's persistent collections are already immutable and don't need\n  cloning.","anchor":"aclone","type":"api","kind":"function"},{"id":"api_add-watch","name":"add-watch","signatures":["(add-watch variable key f)"],"desc":"Adds a watch function to a variable. The watch fn is called when the variable\n  changes with four arguments: key, ref, old-value, new-value.","anchor":"add-watch","type":"api","kind":"function"},{"id":"api_all?","name":"all?","signatures":["(all? pred coll)"],"desc":"Returns true if predicate is true for every element in collection, false otherwise.","anchor":"all","type":"api","kind":"function"},{"id":"api_ancestors","name":"ancestors","signatures":["(ancestors tag)"],"desc":"Returns the set of all transitive ancestors of tag, or nil.","anchor":"ancestors","type":"api","kind":"function"},{"id":"api_and","name":"and","signatures":["(and & args)"],"desc":"Evaluates expressions left to right, returning the first falsy value or the last value.","anchor":"and","type":"api","kind":"macro"},{"id":"api_apply","name":"apply","signatures":["(apply f expr*)"],"desc":"Calls the function with the given arguments. The last argument must be a list of values, which are passed as separate arguments, rather than a single list. Apply returns the result of the calling function.","anchor":"apply","type":"api","kind":"function"},{"id":"api_argv","name":"argv","signatures":[],"desc":"Vector of user arguments passed to the script (excludes program name).\n  Use *program* to get the script path or namespace.","anchor":"argv","type":"api","kind":"function"},{"id":"api_array-map","name":"array-map","signatures":[],"desc":"Constructs a map from the given key\/value pairs. If any keys are\n  equal, later values replace earlier ones, as if by repeated `assoc`.\n  Phel has no distinct array-map type, so the result is the same\n  persistent map as `hash-map` \u2014 `array-map` exists for `.cljc` interop\n  with Clojure sources.","anchor":"array-map","type":"api","kind":"function"},{"id":"api_as->","name":"as->","signatures":["(as-> expr name & forms)"],"desc":"Binds `name` to `expr`, evaluates the first form in the lexical context\n  of that binding, then binds name to that result, repeating for each\n  successive form, returning the result of the last form.","anchor":"as","type":"api","kind":"macro"},{"id":"api_assert","name":"assert","signatures":["(assert expr & [message])"],"desc":"Throws an exception if expr is falsy. Optional message string.\n  Used for precondition checking in application code. When `*assert*`\n  is logical false at macroexpansion time, `assert` expands to nil and\n  performs no runtime check.","anchor":"assert-1","type":"api","kind":"macro"},{"id":"api_assoc","name":"assoc","signatures":["(assoc ds key value & more)"],"desc":"Associates one or more key-value pairs with a collection.\n  Additional key-value pairs beyond the first are applied in order.\n  Throws if an odd number of extra arguments is provided.","anchor":"assoc","type":"api","kind":"function"},{"id":"api_assoc!","name":"assoc!","signatures":["(assoc! tcoll key value & more)"],"desc":"Associates one or more key-value pairs with a transient collection,\n   mutating it in place. Works on transient hash-maps and transient vectors.\n   Variadic forms apply each `key-value` pair in order. Raises\n   `InvalidArgumentException` when `tcoll` is not a supported transient\n   collection or when an odd number of extra arguments is provided.\n   Matches Clojure's `assoc!` semantics.","anchor":"assoc-1","type":"api","kind":"function"},{"id":"api_assoc-in","name":"assoc-in","signatures":["(assoc-in ds [k & ks] v)"],"desc":"Associates a value in a nested data structure at the given path.\n\n  Creates intermediate maps if they don't exist.","anchor":"assoc-in","type":"api","kind":"function"},{"id":"api_associative?","name":"associative?","signatures":["(associative? x)"],"desc":"Returns true if `x` is an associative data structure, false otherwise.\n\n  Associative data structures include vectors, hash maps, structs, and PHP arrays\n  (both indexed and associative), matching Clojure's `Associative` protocol.","anchor":"associative","type":"api","kind":"function"},{"id":"api_atom","name":"atom","signatures":["(atom value)"],"desc":"Creates a new atom with the given value.\n\n  Atoms provide a way to manage mutable state. Use `reset!` to set a new value\n  and `swap!` to update based on the current value.","anchor":"atom","type":"api","kind":"function"},{"id":"api_atom?","name":"atom?","signatures":["(atom? x)"],"desc":"Returns true if the given value is an atom.","anchor":"atom-1","type":"api","kind":"function"},{"id":"api_binding","name":"binding","signatures":["(binding bindings & body)"],"desc":"Temporary redefines definitions while executing the body.\n  The value will be reset after the body was executed.","anchor":"binding","type":"api","kind":"macro"},{"id":"api_bit-and","name":"bit-and","signatures":["(bit-and x y & args)"],"desc":"Bitwise and.","anchor":"bit-and","type":"api","kind":"function"},{"id":"api_bit-clear","name":"bit-clear","signatures":["(bit-clear x n)"],"desc":"Clear bit an index `n`.","anchor":"bit-clear","type":"api","kind":"function"},{"id":"api_bit-flip","name":"bit-flip","signatures":["(bit-flip x n)"],"desc":"Flip bit at index `n`.","anchor":"bit-flip","type":"api","kind":"function"},{"id":"api_bit-not","name":"bit-not","signatures":["(bit-not x)"],"desc":"Bitwise complement.","anchor":"bit-not","type":"api","kind":"function"},{"id":"api_bit-or","name":"bit-or","signatures":["(bit-or x y & args)"],"desc":"Bitwise or.","anchor":"bit-or","type":"api","kind":"function"},{"id":"api_bit-set","name":"bit-set","signatures":["(bit-set x n)"],"desc":"Set bit an index `n`.","anchor":"bit-set","type":"api","kind":"function"},{"id":"api_bit-shift-left","name":"bit-shift-left","signatures":["(bit-shift-left x n)"],"desc":"Bitwise shift left.","anchor":"bit-shift-left","type":"api","kind":"function"},{"id":"api_bit-shift-right","name":"bit-shift-right","signatures":["(bit-shift-right x n)"],"desc":"Bitwise shift right.","anchor":"bit-shift-right","type":"api","kind":"function"},{"id":"api_bit-test","name":"bit-test","signatures":["(bit-test x n)"],"desc":"Test bit at index `n`.","anchor":"bit-test","type":"api","kind":"function"},{"id":"api_bit-xor","name":"bit-xor","signatures":["(bit-xor x y & args)"],"desc":"Bitwise xor.","anchor":"bit-xor","type":"api","kind":"function"},{"id":"api_boolean","name":"boolean","signatures":["(boolean x)"],"desc":"Coerces `x` to a boolean. Returns `false` if `x` is `nil` or `false`,\n   `true` otherwise.","anchor":"boolean","type":"api","kind":"function"},{"id":"api_boolean?","name":"boolean?","signatures":["(boolean? x)"],"desc":"Returns true if `x` is a boolean, false otherwise.","anchor":"boolean-1","type":"api","kind":"function"},{"id":"api_butlast","name":"butlast","signatures":["(butlast coll)"],"desc":"Returns all but the last item in `coll`.","anchor":"butlast","type":"api","kind":"function"},{"id":"api_byte","name":"byte","signatures":["(byte x)"],"desc":"Coerces `x` to a signed 8-bit integer in the range `-128..127`.\n   Decimal values are truncated toward zero (as in Clojure on the JVM).\n   Values outside the range or non-numeric inputs raise\n   `InvalidArgumentException`. Phel has no dedicated byte type, so the\n   result is a plain PHP int \u2014 `byte` exists for `.cljc` interop with\n   Clojure sources.","anchor":"byte","type":"api","kind":"function"},{"id":"api_case","name":"case","signatures":["(case e & pairs)"],"desc":"Evaluates expression and matches it against constant test values, returning the associated result.","anchor":"case","type":"api","kind":"macro"},{"id":"api_cat","name":"cat","signatures":["(cat rf)"],"desc":"A transducer that concatenates the contents of each input into the reduction.","anchor":"cat","type":"api","kind":"function"},{"id":"api_catch","name":"catch","signatures":["(catch exception-type exception-name expr*)"],"desc":"Handle exceptions thrown in a `try` block by matching on the provided exception type. The caught exception is bound to exception-name while evaluating the expressions.","anchor":"catch","type":"api","kind":"function"},{"id":"api_char","name":"char","signatures":["(char x)"],"desc":"Coerces `x` to a single-character string representing the given\n   Unicode code point. Accepts a non-negative integer (the code point,\n   converted via `mb_chr`) or a single-character string, which is\n   returned as-is. Phel has no dedicated char type \u2014 character literals\n   such as `\\A` are already single-character strings \u2014 so the result\n   is always a plain string. Matches Clojure's `char` for `.cljc`\n   interop; raises `InvalidArgumentException` on negative ints,\n   non-single-character strings, and all other inputs.","anchor":"char","type":"api","kind":"function"},{"id":"api_char?","name":"char?","signatures":["(char? x)"],"desc":"Returns true if `x` is a single-character string, false otherwise.\n   Phel has no dedicated character type \u2014 character literals such as\n   `\\A` are already single-character strings \u2014 so `char?` is true for\n   any string of length 1 (UTF-8 counted). Matches ClojureScript's\n   `char?` for `.cljc` interop; Clojure\/JVM's `char?` tests for the\n   distinct `Character` type, which does not exist here.","anchor":"char-1","type":"api","kind":"function"},{"id":"api_coerce-in","name":"coerce-in","signatures":["(coerce-in v min max)"],"desc":"Returns `v` if it is in the range, or `min` if `v` is less than `min`, or `max` if `v` is greater than `max`.","anchor":"coerce-in","type":"api","kind":"function"},{"id":"api_coll?","name":"coll?","signatures":["(coll? x)"],"desc":"Returns true if `x` is a persistent collection \u2014 vector, list, hash-map\n   (including sorted-map), struct, set (including sorted-set), or lazy-seq \u2014\n   and false otherwise. Strings, numbers, `nil`, booleans, keywords, symbols,\n   and plain PHP arrays are not considered collections, matching Clojure's\n   `IPersistentCollection` membership.","anchor":"coll","type":"api","kind":"function"},{"id":"api_comment","name":"comment","signatures":["(comment &)"],"desc":"Ignores the body of the comment.","anchor":"comment","type":"api","kind":"macro"},{"id":"api_comp","name":"comp","signatures":["(comp & fs)"],"desc":"Takes a list of functions and returns a function that is the composition of those functions.","anchor":"comp","type":"api","kind":"function"},{"id":"api_compact","name":"compact","signatures":["(compact coll & values)"],"desc":"Returns a lazy sequence with specified values removed from `coll`.\n  If no values are specified, removes nil values by default.","anchor":"compact","type":"api","kind":"function"},{"id":"api_compare","name":"compare","signatures":["(compare x y)"],"desc":"Wrapper for PHP's spaceship operator (`php\/<=>`).\n  Returns an integer less than, equal to, or greater than zero\n  when `x` is less than, equal to, or greater than `y`, respectively.","anchor":"compare","type":"api","kind":"function"},{"id":"api_compile","name":"compile","signatures":["(compile form)"],"desc":"Returns the compiled PHP code string for the given form.","anchor":"compile","type":"api","kind":"function"},{"id":"api_complement","name":"complement","signatures":["(complement f)"],"desc":"Returns a function that takes the same arguments as `f` and returns the opposite truth value.","anchor":"complement","type":"api","kind":"function"},{"id":"api_completing","name":"completing","signatures":["(completing f & args)"],"desc":"Takes a reducing function `f` of 2 args and returns a fn suitable for transduce\n  by adding a 1-arity (completion) that calls `cf` (default: identity).","anchor":"completing","type":"api","kind":"function"},{"id":"api_concat","name":"concat","signatures":["(concat & colls)"],"desc":"Concatenates multiple collections into a lazy sequence.","anchor":"concat","type":"api","kind":"function"},{"id":"api_cond","name":"cond","signatures":["(cond & pairs)"],"desc":"Evaluates test\/expression pairs, returning the first matching expression.","anchor":"cond","type":"api","kind":"macro"},{"id":"api_cond->","name":"cond->","signatures":["(cond-> expr & clauses)"],"desc":"Takes an expression and a set of test\/form pairs. Threads `expr` (via `->`)\n  through each form for which the corresponding test expression is true.\n  Note that, unlike `cond` branching, `cond->` threading does not short-circuit\n  after the first true test expression.","anchor":"cond-1","type":"api","kind":"macro"},{"id":"api_cond->>","name":"cond->>","signatures":["(cond->> expr & clauses)"],"desc":"Takes an expression and a set of test\/form pairs. Threads `expr` (via `->>`)\n  through each form for which the corresponding test expression is true.\n  Note that, unlike `cond` branching, `cond->>` threading does not short-circuit\n  after the first true test expression.","anchor":"cond-2","type":"api","kind":"macro"},{"id":"api_condp","name":"condp","signatures":["(condp pred expr & clauses)"],"desc":"Takes a binary predicate, an expression, and a set of clauses.\n  Each clause takes the form of either:\n    test-expr result-expr\n    test-expr :>> result-fn\n  For each clause, (pred test-expr expr) is evaluated. If it returns\n  logical true, the clause is a match. If a binary clause is a match,\n  result-expr is returned. If a ternary clause with :>> is a match,\n  the result of (pred test-expr expr) is passed to result-fn and the\n  return value is the result. If no clause matches, the default value\n  is returned (if provided), otherwise an exception is thrown.","anchor":"condp","type":"api","kind":"macro"},{"id":"api_conj","name":"conj","signatures":["(conj)","(conj coll)","(conj coll value)","(conj coll value & more)"],"desc":"Returns a new collection with values added. Appends to vectors\/sets, prepends to lists.","anchor":"conj","type":"api","kind":"function"},{"id":"api_conj!","name":"conj!","signatures":["(conj!)","(conj! tcoll)","(conj! tcoll value)","(conj! tcoll value & more)"],"desc":"Adds `value` to the transient collection `tcoll`, mutating it in place,\n   and returns `tcoll`. The 'addition' may happen at different 'places'\n   depending on the concrete transient type: transient vectors append at\n   the tail, transient hash-sets add the element (no-op if already\n   present), and transient hash-maps treat `value` as a `[key value]`\n   pair (or an associative collection of entries).\n   With zero arguments returns a new empty transient vector. With one\n   argument returns `tcoll` unchanged. Variadic forms reduce `conj!` over\n   the remaining values. Raises `InvalidArgumentException` when `tcoll`\n   is not a transient collection. Matches Clojure's `conj!` semantics.","anchor":"conj-1","type":"api","kind":"function"},{"id":"api_cons","name":"cons","signatures":["(cons x coll)"],"desc":"Prepends an element to the beginning of a collection.","anchor":"cons","type":"api","kind":"function"},{"id":"api_constantly","name":"constantly","signatures":["(constantly x)"],"desc":"Returns a function that always returns `x` and ignores any passed arguments.","anchor":"constantly","type":"api","kind":"function"},{"id":"api_contains-value?","name":"contains-value?","signatures":["(contains-value? coll val)"],"desc":"Returns true if the value is present in the given collection, otherwise returns false.","anchor":"contains-value","type":"api","kind":"function"},{"id":"api_contains?","name":"contains?","signatures":["(contains? coll key)"],"desc":"Returns true if key is present in collection (checks keys\/indices, not values).","anchor":"contains","type":"api","kind":"function"},{"id":"api_count","name":"count","signatures":["(count coll)"],"desc":"Counts the number of elements in a sequence. Can be used on everything that implements the PHP Countable interface.\n\n  Works with lists, vectors, hash-maps, sets, strings, and PHP arrays.\n  Returns 0 for nil.","anchor":"count","type":"api","kind":"function"},{"id":"api_counted?","name":"counted?","signatures":["(counted? coll)"],"desc":"Returns true if `coll` can report its length in constant time \u2014 persistent\n   vectors, lists, hash-maps (including sorted-map), structs, and sets\n   (including sorted-set). Returns false for lazy sequences (counting them\n   requires realizing the whole sequence), strings, numbers, `nil`, and every\n   other non-counted type. Matches Clojure's `counted?` semantics, which\n   mirror the `clojure.lang.Counted` marker interface.","anchor":"counted","type":"api","kind":"function"},{"id":"api_csv-seq","name":"csv-seq","signatures":["(csv-seq filename)","(csv-seq filename options)"],"desc":"Returns a lazy sequence of rows from a CSV file.","anchor":"csv-seq","type":"api","kind":"function"},{"id":"api_cycle","name":"cycle","signatures":["(cycle coll)"],"desc":"Returns an infinite lazy sequence that cycles through the elements of collection.","anchor":"cycle","type":"api","kind":"function"},{"id":"api_dec","name":"dec","signatures":["(dec x)"],"desc":"Decrements `x` by one.","anchor":"dec","type":"api","kind":"function"},{"id":"api_declare","name":"declare","signatures":[],"desc":"Declare a global symbol before it is defined.","anchor":"declare","type":"api","kind":"macro"},{"id":"api_dedupe","name":"dedupe","signatures":["(dedupe & args)"],"desc":"Returns a lazy sequence with consecutive duplicate values removed in `coll`.\n  When called with no args, returns a transducer.","anchor":"dedupe","type":"api","kind":"function"},{"id":"api_deep-merge","name":"deep-merge","signatures":["(deep-merge & args)"],"desc":"Recursively merges data structures.","anchor":"deep-merge","type":"api","kind":"function"},{"id":"api_def","name":"def","signatures":["(def name meta? value)"],"desc":"This special form binds a value to a global symbol.","anchor":"def","type":"api","kind":"function"},{"id":"api_def-","name":"def-","signatures":[],"desc":"Define a private value that will not be exported.","anchor":"def-1","type":"api","kind":"macro"},{"id":"api_defexception","name":"defexception","signatures":["(defexception name)"],"desc":"Define a new exception.","anchor":"defexception","type":"api","kind":"macro"},{"id":"api_defexception*","name":"defexception*","signatures":["(defexception name)"],"desc":"Defines a new exception.","anchor":"defexception-1","type":"api","kind":"function"},{"id":"api_definterface","name":"definterface","signatures":["(definterface name & fns)"],"desc":"An interface in Phel defines an abstract set of functions. It is directly mapped to a PHP interface. An interface can be defined by using the definterface macro.","anchor":"definterface","type":"api","kind":"macro"},{"id":"api_definterface*","name":"definterface*","signatures":["(definterface name & fns)"],"desc":"An interface in Phel defines an abstract set of functions. It is directly mapped to a PHP interface. An interface can be defined by using the definterface macro.","anchor":"definterface-1","type":"api","kind":"function"},{"id":"api_defmacro","name":"defmacro","signatures":[],"desc":"Define a macro.","anchor":"defmacro","type":"api","kind":"macro"},{"id":"api_defmacro-","name":"defmacro-","signatures":["(defmacro- name & fdecl)"],"desc":"Define a private macro that will not be exported.","anchor":"defmacro-1","type":"api","kind":"macro"},{"id":"api_defmethod","name":"defmethod","signatures":["(defmethod multi-name dispatch-val & fn-tail)"],"desc":"Registers a method implementation for a multimethod.\n\n  `multi-name` is the name of the multimethod defined by `defmulti`.\n  When extending a multimethod from a different namespace, fully qualify\n  the multi-name (e.g. `phel\\test\/assert-expr`) so the methods table is\n  resolved in the multimethod's home namespace.\n  `dispatch-val` is the value that triggers this method.\n  `args` and `body` define the function implementation.","anchor":"defmethod","type":"api","kind":"macro"},{"id":"api_defmulti","name":"defmulti","signatures":["(defmulti name dispatch-fn)"],"desc":"Defines a multimethod. `dispatch-fn` is called on the arguments to\n  produce a dispatch value, which is then used to select the appropriate\n  method registered via `defmethod`.\n\n  If no method matches the dispatch value, the `:default` method is used\n  (if defined), otherwise an error is thrown.","anchor":"defmulti","type":"api","kind":"macro"},{"id":"api_defn","name":"defn","signatures":[],"desc":"Define a new global function.","anchor":"defn","type":"api","kind":"macro"},{"id":"api_defn-","name":"defn-","signatures":["(defn- name & fdecl)"],"desc":"Define a private function that will not be exported.","anchor":"defn-1","type":"api","kind":"macro"},{"id":"api_defprotocol","name":"defprotocol","signatures":["(defprotocol protocol-name & method-specs)"],"desc":"Defines a protocol with the given method signatures. Each method signature\n  is a list of (method-name [args]).\n\n  Creates a dispatching function for each method that dispatches on the type\n  of the first argument. Use `extend-type` to add implementations.\n\n  A `:default` type can be registered via `extend-type` as a fallback when\n  no specific type implementation is found.","anchor":"defprotocol","type":"api","kind":"macro"},{"id":"api_defrecord","name":"defrecord","signatures":["(defrecord name fields & impls)"],"desc":"Defines a record type with the given fields, matching Clojure's `defrecord`.\n\n  Expands to a `defstruct` plus Clojure-style factory functions:\n  - `Name` \u2014 positional constructor (from `defstruct`)\n  - `Name?` \u2014 type predicate (from `defstruct`)\n  - `->Name` \u2014 positional factory, identical to `Name`\n  - `map->Name` \u2014 map factory that takes `{:field value ...}`\n\n  An optional tail of protocol\/method forms is spliced into an `extend-type`\n  call, so inline protocol implementations work exactly like Clojure's\n  `defrecord` body. Only Phel protocols are supported in the inline tail;\n  PHP interface implementations remain on `defstruct`.","anchor":"defrecord","type":"api","kind":"macro"},{"id":"api_defstruct","name":"defstruct","signatures":["(defstruct name keys & implementations)"],"desc":"A Struct is a special kind of Map. It only supports a predefined number of keys and is associated to a global name. The Struct not only defines itself but also a predicate function.","anchor":"defstruct","type":"api","kind":"macro"},{"id":"api_defstruct*","name":"defstruct*","signatures":["(defstruct name [keys*])"],"desc":"A Struct is a special kind of Map. It only supports a predefined number of keys and is associated to a global name. The Struct not only defines itself but also a predicate function.","anchor":"defstruct-1","type":"api","kind":"function"},{"id":"api_deftype","name":"deftype","signatures":["(deftype name fields & impls)"],"desc":"Defines a type with the given fields, matching Clojure's `deftype` syntax.\n\n  Expands to a `defstruct` plus a Clojure-style positional factory:\n  - `Name` \u2014 positional constructor (from `defstruct`)\n  - `Name?` \u2014 type predicate (from `defstruct`)\n  - `->Name` \u2014 positional factory, identical to `Name`\n\n  Unlike `defrecord`, no `map->Name` factory is generated.\n\n  An optional tail of protocol\/method forms is spliced into an `extend-type`\n  call. Only Phel protocols are supported in the inline tail.\n\n  Deviation from Clojure: Phel's `deftype` shares the map-backed\n  `defstruct` infrastructure, so instances remain map-like (keys are\n  accessible via `get`). Clojure's `deftype` produces a non-map type;\n  if you need that semantic, use native PHP interop.","anchor":"deftype","type":"api","kind":"macro"},{"id":"api_delay","name":"delay","signatures":["(delay & body)"],"desc":"Takes a body of expressions and yields a Delay object that will invoke the\n  body only the first time it is forced (via force or deref\/@), caching the result.","anchor":"delay","type":"api","kind":"macro"},{"id":"api_delay?","name":"delay?","signatures":["(delay? x)"],"desc":"Returns true if x is a Delay.","anchor":"delay-1","type":"api","kind":"function"},{"id":"api_deref","name":"deref","signatures":["(deref variable & args)"],"desc":"Returns the current value inside the variable.\n\n  With three arguments, and when `variable` is a `PhelFuture`, blocks for\n  at most `timeout-ms` milliseconds waiting for the future to resolve. If\n  the future has not completed within the timeout, returns `timeout-val`.\n  The 3-arg form is only supported on `PhelFuture`.","anchor":"deref","type":"api","kind":"function"},{"id":"api_derive","name":"derive","signatures":["(derive child parent)"],"desc":"Establishes a parent\/child relationship between child and parent keywords\n  in the global hierarchy. Throws on cyclic derivation.","anchor":"derive","type":"api","kind":"function"},{"id":"api_descendants","name":"descendants","signatures":["(descendants tag)"],"desc":"Returns the set of all descendants of tag, or nil.","anchor":"descendants","type":"api","kind":"function"},{"id":"api_difference","name":"difference","signatures":["(difference set & sets)"],"desc":"Difference between multiple sets into a new one.","anchor":"difference","type":"api","kind":"function"},{"id":"api_disj","name":"disj","signatures":["(disj set)","(disj set k)","(disj set k & ks)"],"desc":"Returns a new set that does not contain the given key(s). Works on hash-sets and sorted-sets.\n  Removing a non-existent key is a no-op. Returns `nil` when called on `nil`.","anchor":"disj","type":"api","kind":"function"},{"id":"api_disj!","name":"disj!","signatures":["(disj! tcoll)","(disj! tcoll value)","(disj! tcoll value & more)"],"desc":"Removes one or more elements from a transient set, mutating it in place.\n   Raises `InvalidArgumentException` when `tcoll` is not a transient set.\n   Matches Clojure's `disj!` semantics.","anchor":"disj-1","type":"api","kind":"function"},{"id":"api_dissoc","name":"dissoc","signatures":["(dissoc ds key)"],"desc":"Dissociates `key` from the datastructure `ds`. Returns `ds` without `key`.","anchor":"dissoc","type":"api","kind":"function"},{"id":"api_dissoc!","name":"dissoc!","signatures":["(dissoc! tcoll)","(dissoc! tcoll key)","(dissoc! tcoll key & ks)"],"desc":"Dissociates one or more keys from a transient map, mutating it in place.\n   Raises `InvalidArgumentException` when `tcoll` is not a transient map.\n   Matches Clojure's `dissoc!` semantics.","anchor":"dissoc-1","type":"api","kind":"function"},{"id":"api_dissoc-in","name":"dissoc-in","signatures":["(dissoc-in ds [k & ks])"],"desc":"Dissociates a value from a nested data structure at the given path.","anchor":"dissoc-in","type":"api","kind":"function"},{"id":"api_distinct","name":"distinct","signatures":["(distinct & args)"],"desc":"Returns a lazy sequence with duplicated values removed in `coll`.\n  When called with no args, returns a transducer.","anchor":"distinct","type":"api","kind":"function"},{"id":"api_do","name":"do","signatures":["(do expr*)"],"desc":"Evaluates the expressions in order and returns the value of the last expression. If no expression is given, nil is returned.","anchor":"do","type":"api","kind":"function"},{"id":"api_doall","name":"doall","signatures":["(doall coll)"],"desc":"Forces realization of a lazy sequence and returns it as a vector.","anchor":"doall","type":"api","kind":"function"},{"id":"api_dofor","name":"dofor","signatures":["(dofor head & body)"],"desc":"Repeatedly executes body for side effects with bindings and modifiers as\n  provided by for. Returns nil.","anchor":"dofor","type":"api","kind":"macro"},{"id":"api_dorun","name":"dorun","signatures":["(dorun coll)"],"desc":"Forces realization of a lazy sequence for side effects, returns nil.","anchor":"dorun","type":"api","kind":"function"},{"id":"api_doseq","name":"doseq","signatures":["(doseq seq-exprs & body)"],"desc":"Alias for `dofor`.","anchor":"doseq","type":"api","kind":"macro"},{"id":"api_dotimes","name":"dotimes","signatures":["(dotimes [binding n] & body)"],"desc":"Evaluates body `n` times with `binding` bound to integers from 0 to n-1.\n  Returns nil.","anchor":"dotimes","type":"api","kind":"macro"},{"id":"api_doto","name":"doto","signatures":["(doto x & forms)"],"desc":"Evaluates x then calls all of the methods and functions with the\n  value of x supplied at the front of the given arguments. The forms\n  are evaluated in order. Returns x.","anchor":"doto","type":"api","kind":"macro"},{"id":"api_double","name":"double","signatures":["(double x)"],"desc":"Coerces `x` to a double. In PHP there is no distinction between float and\n   double; both map to the same native PHP float type. Alias for `float`.","anchor":"double","type":"api","kind":"function"},{"id":"api_double?","name":"double?","signatures":["(double? x)"],"desc":"Returns true if `x` is a floating-point number, false otherwise.\n   Alias for `float?`, matching Clojure's `double?` naming. Since Phel\n   uses PHP floats (IEEE 754 doubles) there is no separate single-precision\n   float type.","anchor":"double-1","type":"api","kind":"function"},{"id":"api_drop","name":"drop","signatures":["(drop n & args)"],"desc":"Drops the first `n` elements of `coll`. Returns a lazy sequence.\n  When called with n only, returns a transducer.","anchor":"drop","type":"api","kind":"function"},{"id":"api_drop-last","name":"drop-last","signatures":["(drop-last coll)","(drop-last n coll)"],"desc":"Drops the last `n` elements of `coll`. `n` defaults to `1` when omitted,\n   matching Clojure's `(drop-last coll)` single-arity form. Returns an empty\n   vector when `coll` is `nil`, matching Clojure's `(drop-last n nil)` \u2192 `()`\n   and aligning with `drop`\/`take`, which also return an empty result on `nil`.","anchor":"drop-last","type":"api","kind":"function"},{"id":"api_drop-while","name":"drop-while","signatures":["(drop-while pred & args)"],"desc":"Drops all elements at the front of `coll` where `(pred x)` is true. Returns a lazy sequence.\n  When called with pred only, returns a transducer.","anchor":"drop-while","type":"api","kind":"function"},{"id":"api_empty?","name":"empty?","signatures":["(empty? x)"],"desc":"Returns true if x would be 0, \"\" or empty collection, false otherwise.","anchor":"empty","type":"api","kind":"function"},{"id":"api_eval","name":"eval","signatures":["(eval form)"],"desc":"Evaluates a form and return the evaluated results.","anchor":"eval","type":"api","kind":"function"},{"id":"api_even?","name":"even?","signatures":["(even? x)"],"desc":"Checks if `x` is even.","anchor":"even","type":"api","kind":"function"},{"id":"api_every?","name":"every?","signatures":["(every? pred coll)"],"desc":"Returns true if predicate is true for every element in collection, false otherwise.\n  Alias for `all?`.","anchor":"every","type":"api","kind":"function"},{"id":"api_ex-cause","name":"ex-cause","signatures":["(ex-cause ex)"],"desc":"Returns the cause of an exception, or nil.","anchor":"ex-cause","type":"api","kind":"function"},{"id":"api_ex-data","name":"ex-data","signatures":["(ex-data ex)"],"desc":"Returns the data map from an ex-info exception, or nil if not an ExInfoException.","anchor":"ex-data","type":"api","kind":"function"},{"id":"api_ex-info","name":"ex-info","signatures":["(ex-info msg data)","(ex-info msg data cause)"],"desc":"Creates an exception with a message and a data map. Optionally takes a cause.","anchor":"ex-info","type":"api","kind":"function"},{"id":"api_ex-message","name":"ex-message","signatures":["(ex-message ex)"],"desc":"Returns the message of an exception.","anchor":"ex-message","type":"api","kind":"function"},{"id":"api_extend-protocol","name":"extend-protocol","signatures":["(extend-protocol protocol-name & specs)"],"desc":"Convenience macro that extends a single protocol to multiple types.\n  Alternates type-specs and method implementations.\n\n  Equivalent to multiple `extend-type` calls.","anchor":"extend-protocol","type":"api","kind":"macro"},{"id":"api_extend-type","name":"extend-type","signatures":["(extend-type type-spec & specs)"],"desc":"Extends a type with protocol method implementations.\n\n  type-spec can be:\n  - `nil` for the nil type\n  - a type keyword matching what `type` returns: `:string`, `:int`, `:float`,\n    `:boolean`, `:keyword`, `:symbol`, `:vector`, `:list`, `:hash-map`, `:set`,\n    `:var`, `:function`, `:php\/array`\n  - a symbol for struct names (resolved in current namespace)\n  - a string for explicit PHP class names (cross-namespace structs)\n\n  Note: `:struct` and `:php\/object` cannot be used as type-specs because\n  protocol dispatch resolves these to their specific PHP class names.\n  Use a struct symbol or PHP class name string instead.","anchor":"extend-type","type":"api","kind":"macro"},{"id":"api_extends?","name":"extends?","signatures":["(extends? protocol type-key)"],"desc":"Returns true if the given type-key has implementations for all methods\n  of the protocol. type-key should match what protocol-type-key returns.","anchor":"extends","type":"api","kind":"function"},{"id":"api_extreme","name":"extreme","signatures":["(extreme order args)"],"desc":"Returns the most extreme value in `args` based on the binary `order` function.","anchor":"extreme","type":"api","kind":"function"},{"id":"api_false?","name":"false?","signatures":["(false? x)"],"desc":"Checks if value is exactly false (not just falsy).","anchor":"false","type":"api","kind":"function"},{"id":"api_ffirst","name":"ffirst","signatures":["(ffirst coll)"],"desc":"Same as `(first (first coll))`.","anchor":"ffirst","type":"api","kind":"function"},{"id":"api_file-seq","name":"file-seq","signatures":["(file-seq path)"],"desc":"Returns a lazy sequence of all files and directories in a directory tree.","anchor":"file-seq","type":"api","kind":"function"},{"id":"api_filter","name":"filter","signatures":["(filter pred & args)"],"desc":"Returns a lazy sequence of elements where predicate returns true.\n  When called with pred only, returns a transducer.","anchor":"filter","type":"api","kind":"function"},{"id":"api_finally","name":"finally","signatures":["(finally expr*)"],"desc":"Evaluate expressions after the try body and all matching catches have completed. The finally block runs regardless of whether an exception was thrown.","anchor":"finally","type":"api","kind":"function"},{"id":"api_find","name":"find","signatures":["(find pred coll)"],"desc":"Returns the first item in `coll` where `(pred item)` evaluates to true.","anchor":"find","type":"api","kind":"function"},{"id":"api_find-hierarchy-method","name":"find-hierarchy-method","signatures":["(find-hierarchy-method methods dispatch-val)"],"desc":"Finds the best matching method for dispatch-val using the global hierarchy.\n  Returns the method function or nil. Used internally by defmulti.","anchor":"find-hierarchy-method","type":"api","kind":"function"},{"id":"api_find-index","name":"find-index","signatures":["(find-index pred coll)"],"desc":"Returns the index of the first item in `coll` where `(pred item)` evaluates to true.","anchor":"find-index","type":"api","kind":"function"},{"id":"api_first","name":"first","signatures":[],"desc":"Returns the first element of a sequence, or nil if empty.","anchor":"first","type":"api","kind":"function"},{"id":"api_flatten","name":"flatten","signatures":["(flatten coll)"],"desc":"Flattens nested sequential structure into a lazy sequence of all leaf values.","anchor":"flatten","type":"api","kind":"function"},{"id":"api_float","name":"float","signatures":["(float x)"],"desc":"Coerces `x` to a float. In PHP there is no distinction between float and\n   double; both map to the same native PHP float type. Delegates to PHP's\n   `floatval`, so non-numeric strings return `0.0` and `nil` returns `0.0`.","anchor":"float","type":"api","kind":"function"},{"id":"api_float?","name":"float?","signatures":["(float? x)"],"desc":"Returns true if `x` is float point number, false otherwise.","anchor":"float-1","type":"api","kind":"function"},{"id":"api_fn","name":"fn","signatures":["(fn [params*] expr*)"],"desc":"Defines a function. A function consists of a list of parameters and a list of expression. The value of the last expression is returned as the result of the function. All other expression are only evaluated for side effects. If no expression is given, the function returns nil.","anchor":"fn","type":"api","kind":"function"},{"id":"api_fn?","name":"fn?","signatures":["(fn? x)"],"desc":"Returns true if `x` is a function, false otherwise.","anchor":"fn-1","type":"api","kind":"function"},{"id":"api_fnil","name":"fnil","signatures":["(fnil f & defaults)"],"desc":"Returns a function that replaces nil arguments with the provided defaults\n  before calling f. The number of defaults determines how many leading arguments\n  are nil-checked.","anchor":"fnil","type":"api","kind":"function"},{"id":"api_for","name":"for","signatures":["(for head & body)"],"desc":"List comprehension. The head of the loop is a vector that contains a\n  sequence of bindings modifiers and options. A binding is a sequence of three\n  values `binding :verb expr`. Where `binding` is a binding as\n  in let and `:verb` is one of the following keywords:\n\n  * `:range` loop over a range by using the range function.\n  * `:in` loops over all values of a collection (including strings).\n  * `:keys` loops over all keys\/indexes of a collection.\n  * `:pairs` loops over all key-value pairs of a collection.\n\n  After each loop binding, additional modifiers can be applied. Modifiers\n  have the form `:modifier argument`. The following modifiers are supported:\n\n  * `:while` breaks the loop if the expression is falsy.\n  * `:let` defines additional bindings.\n  * `:when` only evaluates the loop body if the condition is true.\n\n  Finally, additional options can be set:\n\n  * `:reduce [accumulator initial-value]` Instead of returning a list,\n     it reduces the values into `accumulator`. Initially `accumulator`\n     is bound to `initial-value`.","anchor":"for","type":"api","kind":"macro"},{"id":"api_force","name":"force","signatures":["(force x)"],"desc":"If x is a Delay, forces it and returns its cached value. Otherwise returns x.","anchor":"force","type":"api","kind":"function"},{"id":"api_foreach","name":"foreach","signatures":["(foreach [value valueExpr] expr*)","(foreach [key value valueExpr] expr*)"],"desc":"The foreach special form can be used to iterate over all kind of PHP datastructures. The return value of foreach is always nil. The loop special form should be preferred of the foreach special form whenever possible.","anchor":"foreach","type":"api","kind":"function"},{"id":"api_format","name":"format","signatures":["(format fmt & xs)"],"desc":"Returns a formatted string. See PHP's <i>sprintf<\/i> for more information.","anchor":"format","type":"api","kind":"function"},{"id":"api_frequencies","name":"frequencies","signatures":["(frequencies coll)"],"desc":"Returns a map from distinct items in `coll` to the number of times they appear.\n\n  Works with vectors, lists, sets, and strings.","anchor":"frequencies","type":"api","kind":"function"},{"id":"api_full-name","name":"full-name","signatures":["(full-name x)"],"desc":"Return the namespace and name string of a string, keyword or symbol.","anchor":"full-name","type":"api","kind":"function"},{"id":"api_function?","name":"function?","signatures":["(function? x)"],"desc":"Returns true if `x` is a function, false otherwise.","anchor":"function","type":"api","kind":"function"},{"id":"api_gensym","name":"gensym","signatures":["(gensym)"],"desc":"Generates a new unique symbol.","anchor":"gensym","type":"api","kind":"function"},{"id":"api_get","name":"get","signatures":["(get ds k & [opt])"],"desc":"Gets the value at key in a collection. Returns default if not found.","anchor":"get","type":"api","kind":"function"},{"id":"api_get-in","name":"get-in","signatures":["(get-in ds ks & [opt])"],"desc":"Accesses a value in a nested data structure via a sequence of keys.\n\n  Returns `opt` (default nil) if the path doesn't exist.","anchor":"get-in","type":"api","kind":"function"},{"id":"api_get-validator","name":"get-validator","signatures":["(get-validator variable)"],"desc":"Returns the validator function of a variable, or nil.","anchor":"get-validator","type":"api","kind":"function"},{"id":"api_group-by","name":"group-by","signatures":["(group-by f coll)"],"desc":"Returns a map of the elements of coll keyed by the result of `f` on each element.","anchor":"group-by","type":"api","kind":"function"},{"id":"api_hash-map","name":"hash-map","signatures":["(hash-map & xs)"],"desc":"Creates a new hash map. If no argument is provided, an empty hash map is created. The number of parameters must be even.","anchor":"hash-map","type":"api","kind":"function"},{"id":"api_hash-map?","name":"hash-map?","signatures":["(hash-map? x)"],"desc":"Returns true if `x` is a hash map, false otherwise.","anchor":"hash-map-1","type":"api","kind":"function"},{"id":"api_hash-set","name":"hash-set","signatures":["(hash-set & xs)"],"desc":"Creates a new Set from the given arguments. Shortcut: #{}","anchor":"hash-set","type":"api","kind":"function"},{"id":"api_id","name":"id","signatures":["(id a & more)"],"desc":"Checks if all values are identical. Same as `a === b` in PHP.","anchor":"id","type":"api","kind":"function"},{"id":"api_identical?","name":"identical?","signatures":["(identical? a & more)"],"desc":"Checks if all values are identical. Same as `a === b` in PHP.","anchor":"identical","type":"api","kind":"function"},{"id":"api_identity","name":"identity","signatures":["(identity x)"],"desc":"Returns its argument.","anchor":"identity","type":"api","kind":"function"},{"id":"api_if","name":"if","signatures":["(if test then else?)"],"desc":"A control flow structure. First evaluates test. If test evaluates to true, only the then form is evaluated and the result is returned. If test evaluates to false only the else form is evaluated and the result is returned. If no else form is given, nil will be returned.","anchor":"if","type":"api","kind":"function"},{"id":"api_if-let","name":"if-let","signatures":["(if-let bindings then & [else])"],"desc":"If test is true, evaluates then with binding-form bound to the value of test,\n  if not, yields else","anchor":"if-let","type":"api","kind":"macro"},{"id":"api_if-not","name":"if-not","signatures":["(if-not test then & [else])"],"desc":"Evaluates then if test is false, else otherwise.","anchor":"if-not","type":"api","kind":"macro"},{"id":"api_if-some","name":"if-some","signatures":["(if-some bindings then & [else])"],"desc":"Binds name to the value of test. If test is not nil, evaluates then with binding-form\n  bound to the value of test, if not, yields else. Unlike if-let, false and 0 are not\n  treated as falsy \u2014 only nil triggers the else branch.","anchor":"if-some","type":"api","kind":"macro"},{"id":"api_inc","name":"inc","signatures":["(inc x)"],"desc":"Increments `x` by one.","anchor":"inc","type":"api","kind":"function"},{"id":"api_indexed?","name":"indexed?","signatures":["(indexed? x)"],"desc":"Returns true if `x` is an indexed sequence, false otherwise.\n\n  Indexed sequences include lists, vectors, and indexed PHP arrays.","anchor":"indexed","type":"api","kind":"function"},{"id":"api_inf?","name":"inf?","signatures":["(inf? x)"],"desc":"Checks if `x` is infinite.","anchor":"inf","type":"api","kind":"function"},{"id":"api_int?","name":"int?","signatures":["(int? x)"],"desc":"Returns true if `x` is an integer number, false otherwise.\n   Alias for `integer?`.\n\n   Note that, unlike Clojure, Phel uses PHP integers and there is no\n   distinction between standard and fixed-precision integers.\n   Integer sizes are also limited by platform (see php\/PHP_INT_MAX constant).","anchor":"int","type":"api","kind":"function"},{"id":"api_integer?","name":"integer?","signatures":["(integer? x)"],"desc":"Returns true if `x` is an integer number, false otherwise.","anchor":"integer","type":"api","kind":"function"},{"id":"api_interleave","name":"interleave","signatures":["(interleave & colls)"],"desc":"Interleaves multiple collections. Returns a lazy sequence.\n\n  Returns elements by taking one from each collection in turn.\n  Pads with nil when collections have different lengths.\n  Works with infinite sequences.","anchor":"interleave","type":"api","kind":"function"},{"id":"api_interpose","name":"interpose","signatures":["(interpose sep & args)"],"desc":"Returns elements separated by a separator. Returns a lazy sequence.\n  When called with sep only, returns a transducer.","anchor":"interpose","type":"api","kind":"function"},{"id":"api_intersection","name":"intersection","signatures":["(intersection set & sets)"],"desc":"Intersect multiple sets into a new one.","anchor":"intersection","type":"api","kind":"function"},{"id":"api_into","name":"into","signatures":["(into to & rest)"],"desc":"Returns `to` with all elements of `from` added.\n\n  When `from` is associative, it is treated as a sequence of key-value pairs.\n  Supports persistent and transient collections.","anchor":"into","type":"api","kind":"function"},{"id":"api_invert","name":"invert","signatures":["(invert map)"],"desc":"Returns a new map where the keys and values are swapped.\n\n  If map has duplicated values, some keys will be ignored.","anchor":"invert","type":"api","kind":"function"},{"id":"api_isa?","name":"isa?","signatures":["(isa? child parent)"],"desc":"Returns true if child equals parent, or child is a descendant of parent\n  in the global hierarchy.","anchor":"isa","type":"api","kind":"function"},{"id":"api_iterate","name":"iterate","signatures":["(iterate f x)"],"desc":"Returns an infinite lazy sequence of x, (f x), (f (f x)), and so on.","anchor":"iterate","type":"api","kind":"function"},{"id":"api_iteration","name":"iteration","signatures":["(iteration step opts)"],"desc":"Creates a lazy sequence from successive calls to `step`.\n  `step` is called with a key (starting with `:initk`) and returns a result.\n  `:kf` extracts the next key, `:vf` extracts the value from the result.\n  Terminates when the result is nil.\n\n  Options map keys:\n    :kf     \u2014 key function (default: identity)\n    :vf     \u2014 value function (default: identity)\n    :initk  \u2014 initial key (default: nil)","anchor":"iteration","type":"api","kind":"function"},{"id":"api_juxt","name":"juxt","signatures":["(juxt & fs)"],"desc":"Takes a list of functions and returns a new function that is the juxtaposition of those functions.","anchor":"juxt","type":"api","kind":"function"},{"id":"api_keep","name":"keep","signatures":["(keep pred & args)"],"desc":"Returns a lazy sequence of non-nil results of applying function to elements.\n  When called with f only, returns a transducer.","anchor":"keep","type":"api","kind":"function"},{"id":"api_keep-indexed","name":"keep-indexed","signatures":["(keep-indexed pred & args)"],"desc":"Returns a lazy sequence of non-nil results of `(pred i x)`.\n  When called with f only, returns a transducer.","anchor":"keep-indexed","type":"api","kind":"function"},{"id":"api_keys","name":"keys","signatures":["(keys coll)"],"desc":"Returns a sequence of all keys in a map.","anchor":"keys","type":"api","kind":"function"},{"id":"api_keyword","name":"keyword","signatures":["(keyword x)"],"desc":"Creates a new Keyword from a given string.","anchor":"keyword","type":"api","kind":"function"},{"id":"api_keyword?","name":"keyword?","signatures":["(keyword? x)"],"desc":"Returns true if `x` is a keyword, false otherwise.","anchor":"keyword-1","type":"api","kind":"function"},{"id":"api_kvs","name":"kvs","signatures":["(kvs coll)"],"desc":"Returns a vector of key-value pairs like `[k1 v1 k2 v2 k3 v3 ...]`.","anchor":"kvs","type":"api","kind":"function"},{"id":"api_last","name":"last","signatures":["(last coll)"],"desc":"Returns the last element of `coll` or nil if `coll` is empty or nil.","anchor":"last","type":"api","kind":"function"},{"id":"api_lazy-cat","name":"lazy-cat","signatures":["(lazy-cat & colls)"],"desc":"Concatenates collections into a lazy sequence (expands to concat).","anchor":"lazy-cat","type":"api","kind":"macro"},{"id":"api_lazy-seq","name":"lazy-seq","signatures":["(lazy-seq & body)"],"desc":"Creates a lazy sequence that evaluates the body only when accessed.","anchor":"lazy-seq","type":"api","kind":"macro"},{"id":"api_let","name":"let","signatures":["(let [bindings*] expr*)"],"desc":"Creates a new lexical context with assignments defined in bindings. Afterwards the list of expressions is evaluated and the value of the last expression is returned. If no expression is given nil is returned.","anchor":"let","type":"api","kind":"function"},{"id":"api_letfn","name":"letfn","signatures":["(letfn bindings & body)"],"desc":"Defines mutually recursive local functions.\n\n  bindings is a vector of function specs: (letfn [(f [params] body) (g [params] body)] expr)\n  All function names are in scope within all function bodies and the body expression,\n  enabling mutual recursion.","anchor":"letfn","type":"api","kind":"macro"},{"id":"api_line-seq","name":"line-seq","signatures":["(line-seq filename)"],"desc":"Returns a lazy sequence of lines from a file.","anchor":"line-seq","type":"api","kind":"function"},{"id":"api_list","name":"list","signatures":["(list & xs)"],"desc":"Creates a new list. If no argument is provided, an empty list is created.","anchor":"list","type":"api","kind":"function"},{"id":"api_list?","name":"list?","signatures":["(list? x)"],"desc":"Returns true if `x` is a list, false otherwise.","anchor":"list-1","type":"api","kind":"function"},{"id":"api_loop","name":"loop","signatures":["(loop [bindings*] expr*)"],"desc":"Creates a new lexical context with variables defined in bindings and defines a recursion point at the top of the loop.","anchor":"loop","type":"api","kind":"function"},{"id":"api_macroexpand","name":"macroexpand","signatures":["(macroexpand form)"],"desc":"Recursively expands the given form until it is no longer a macro call.","anchor":"macroexpand","type":"api","kind":"function"},{"id":"api_macroexpand-1","name":"macroexpand-1","signatures":["(macroexpand-1 form)"],"desc":"Expands the given form once if it is a macro call.","anchor":"macroexpand-1","type":"api","kind":"function"},{"id":"api_make-hierarchy","name":"make-hierarchy","signatures":["(make-hierarchy)"],"desc":"Returns a new hierarchy map with no parent relationships.","anchor":"make-hierarchy","type":"api","kind":"function"},{"id":"api_map","name":"map","signatures":["(map f & colls)"],"desc":"Returns a lazy sequence of the result of applying `f` to all of the first items in each coll,\n   followed by applying `f` to all the second items in each coll until anyone of the colls is exhausted.\n\n  When given a single collection, applies the function to each element.\n  With multiple collections, applies the function to corresponding elements from each collection,\n  stopping when the shortest collection is exhausted.","anchor":"map","type":"api","kind":"function"},{"id":"api_map-indexed","name":"map-indexed","signatures":["(map-indexed f coll)"],"desc":"Maps a function over a collection with index. Returns a lazy sequence.\n\n  Applies `f` to each element in `xs`. `f` is a two-argument function where\n  the first argument is the index (0-based) and the second is the element itself.\n  Works with infinite sequences.","anchor":"map-indexed","type":"api","kind":"function"},{"id":"api_map?","name":"map?","signatures":["(map? x)"],"desc":"Returns true if `x` is a hash map, false otherwise.","anchor":"map-1","type":"api","kind":"function"},{"id":"api_mapcat","name":"mapcat","signatures":["(mapcat f & args)"],"desc":"Maps a function over a collection and concatenates the results. Returns a lazy sequence.\n  When called with f only, returns a transducer.","anchor":"mapcat","type":"api","kind":"function"},{"id":"api_max","name":"max","signatures":["(max & numbers)"],"desc":"Returns the numeric maximum of all numbers.","anchor":"max","type":"api","kind":"function"},{"id":"api_max-key","name":"max-key","signatures":["(max-key k x & more)"],"desc":"Returns the arg for which (k arg) is largest. On ties, returns the latest argument, matching Clojure semantics.","anchor":"max-key","type":"api","kind":"function"},{"id":"api_mean","name":"mean","signatures":["(mean xs)"],"desc":"Returns the mean of `xs`.","anchor":"mean","type":"api","kind":"function"},{"id":"api_median","name":"median","signatures":["(median xs)"],"desc":"Returns the median of `xs`.","anchor":"median","type":"api","kind":"function"},{"id":"api_memoize","name":"memoize","signatures":["(memoize f)"],"desc":"Returns a memoized version of the function `f`. The memoized function\n  caches the return value for each set of arguments.","anchor":"memoize","type":"api","kind":"function"},{"id":"api_memoize-lru","name":"memoize-lru","signatures":["(memoize-lru f)","(memoize-lru f max-size)"],"desc":"Returns a memoized version of the function `f` with an LRU (Least Recently Used)\n  cache limited to `max-size` entries. When the cache exceeds `max-size`, the\n  least recently used entry is evicted. This prevents unbounded memory growth\n  in long-running processes.\n\n  Without arguments, uses a default cache size of 128 entries.","anchor":"memoize-lru","type":"api","kind":"function"},{"id":"api_merge","name":"merge","signatures":["(merge & maps)"],"desc":"Merges multiple maps into one new map.\n\n  If a key appears in more than one collection, later values replace previous ones.","anchor":"merge","type":"api","kind":"function"},{"id":"api_merge-with","name":"merge-with","signatures":["(merge-with f & hash-maps)"],"desc":"Merges multiple maps into one new map. If a key appears in more than one\n   collection, the result of `(f current-val next-val)` is used.","anchor":"merge-with","type":"api","kind":"function"},{"id":"api_meta","name":"meta","signatures":[],"desc":"Gets the metadata attached to a value.\n  For a quoted symbol (`(meta 'foo)`) the definition metadata registered via `def` is returned.\n  For any other expression the value is looked up at runtime and its `MetaInterface` metadata returned.","anchor":"meta","type":"api","kind":"macro"},{"id":"api_min","name":"min","signatures":["(min & numbers)"],"desc":"Returns the numeric minimum of all numbers.","anchor":"min","type":"api","kind":"function"},{"id":"api_min-key","name":"min-key","signatures":["(min-key k x & more)"],"desc":"Returns the arg for which (k arg) is smallest. On ties, returns the latest argument, matching Clojure semantics.","anchor":"min-key","type":"api","kind":"function"},{"id":"api_name","name":"name","signatures":["(name x)"],"desc":"Returns the name string of a string, keyword or symbol.","anchor":"name","type":"api","kind":"function"},{"id":"api_namespace","name":"namespace","signatures":["(namespace x)"],"desc":"Return the namespace string of a symbol or keyword. Nil if not present.","anchor":"namespace","type":"api","kind":"function"},{"id":"api_nan?","name":"nan?","signatures":["(nan? x)"],"desc":"Checks if `x` is not a number.","anchor":"nan-2","type":"api","kind":"function"},{"id":"api_neg?","name":"neg?","signatures":["(neg? x)"],"desc":"Checks if `x` is smaller than zero.","anchor":"neg","type":"api","kind":"function"},{"id":"api_next","name":"next","signatures":[],"desc":"Returns the sequence after the first element, or nil if empty.","anchor":"next","type":"api","kind":"function"},{"id":"api_nfirst","name":"nfirst","signatures":["(nfirst coll)"],"desc":"Same as `(next (first coll))`.","anchor":"nfirst","type":"api","kind":"function"},{"id":"api_nil?","name":"nil?","signatures":["(nil? x)"],"desc":"Returns true if value is nil, false otherwise.","anchor":"nil","type":"api","kind":"function"},{"id":"api_nnext","name":"nnext","signatures":["(nnext coll)"],"desc":"Same as `(next (next coll))`.","anchor":"nnext","type":"api","kind":"function"},{"id":"api_not","name":"not","signatures":["(not x)"],"desc":"Returns true if value is falsy (nil or false), false otherwise.","anchor":"not","type":"api","kind":"function"},{"id":"api_not-any?","name":"not-any?","signatures":["(not-any? pred coll)"],"desc":"Returns true if `(pred x)` is logical false for every `x` in `coll`\n   or if `coll` is empty. Otherwise returns false.","anchor":"not-any","type":"api","kind":"function"},{"id":"api_not-empty","name":"not-empty","signatures":["(not-empty coll)"],"desc":"Returns `coll` if it contains elements, otherwise nil.","anchor":"not-empty","type":"api","kind":"function"},{"id":"api_not-every?","name":"not-every?","signatures":["(not-every? pred coll)"],"desc":"Returns false if `(pred x)` is logical true for every `x` in collection `coll`\n   or if `coll` is empty. Otherwise returns true.","anchor":"not-every","type":"api","kind":"function"},{"id":"api_not=","name":"not=","signatures":["(not= a & more)"],"desc":"Checks if all values are unequal. Same as `a != b` in PHP.","anchor":"not-1","type":"api","kind":"function"},{"id":"api_ns","name":"ns","signatures":["(ns name imports*)"],"desc":"Defines the namespace for the current file and adds imports to the environment. Imports can either be uses or requires. The keyword :use is used to import PHP classes, the keyword :require is used to import Phel modules and the keyword :require-file is used to load php files.","anchor":"ns-1","type":"api","kind":"function"},{"id":"api_number?","name":"number?","signatures":["(number? x)"],"desc":"Returns true if `x` is a number, false otherwise.","anchor":"number","type":"api","kind":"function"},{"id":"api_object-array","name":"object-array","signatures":["(object-array size-or-seq)"],"desc":"Creates a PHP array of the given size initialized to `nil`, or a PHP\n  array containing the elements of the given sequence. Matches Clojure's\n  `object-array` for `.cljc` interop \u2014 in Phel the result is a plain PHP\n  array (accessible via `php\/aget`\/`php\/aset`) since PHP has no typed\n  array distinction.","anchor":"object-array","type":"api","kind":"function"},{"id":"api_odd?","name":"odd?","signatures":["(odd? x)"],"desc":"Checks if `x` is odd.","anchor":"odd","type":"api","kind":"function"},{"id":"api_one?","name":"one?","signatures":["(one? x)"],"desc":"Checks if `x` is one.","anchor":"one","type":"api","kind":"function"},{"id":"api_or","name":"or","signatures":["(or & args)"],"desc":"Evaluates expressions left to right, returning the first truthy value or the last value.","anchor":"or","type":"api","kind":"macro"},{"id":"api_pairs","name":"pairs","signatures":["(pairs coll)"],"desc":"Gets the pairs of an associative data structure.","anchor":"pairs","type":"api","kind":"function"},{"id":"api_parents","name":"parents","signatures":["(parents tag)"],"desc":"Returns the set of immediate parents of tag in the global hierarchy, or nil.","anchor":"parents","type":"api","kind":"function"},{"id":"api_parse-boolean","name":"parse-boolean","signatures":["(parse-boolean s)"],"desc":"Parses a string as a boolean. Returns true for \"true\", false for \"false\", nil otherwise.","anchor":"parse-boolean","type":"api","kind":"function"},{"id":"api_parse-double","name":"parse-double","signatures":["(parse-double s)"],"desc":"Parses a string as a float. Returns nil if parsing fails.","anchor":"parse-double","type":"api","kind":"function"},{"id":"api_parse-long","name":"parse-long","signatures":["(parse-long s)"],"desc":"Parses a string as an integer. Returns nil if parsing fails.","anchor":"parse-long","type":"api","kind":"function"},{"id":"api_partial","name":"partial","signatures":["(partial f & args)"],"desc":"Takes a function `f` and fewer than normal arguments of `f` and returns a function\n  that a variable number of additional arguments. When call `f` will be called\n  with `args` and the additional arguments.","anchor":"partial","type":"api","kind":"function"},{"id":"api_partition","name":"partition","signatures":["(partition n coll)"],"desc":"Partitions collection into chunks of size n, dropping incomplete final partition.","anchor":"partition","type":"api","kind":"function"},{"id":"api_partition-all","name":"partition-all","signatures":["(partition-all n coll)"],"desc":"Partitions collection into chunks of size n, including incomplete final partition.","anchor":"partition-all","type":"api","kind":"function"},{"id":"api_partition-by","name":"partition-by","signatures":["(partition-by f coll)"],"desc":"Returns a lazy sequence of partitions. Applies `f` to each value in `coll`, splitting them each time the return value changes.","anchor":"partition-by","type":"api","kind":"function"},{"id":"api_peek","name":"peek","signatures":["(peek coll)"],"desc":"Returns the last element of a sequence, or nil if empty or nil.\n  Works on vectors, PHP arrays, lists, and lazy sequences.","anchor":"peek","type":"api","kind":"function"},{"id":"api_persistent","name":"persistent","signatures":["(persistent coll)"],"desc":"Converts a transient collection back to a persistent collection.","anchor":"persistent","type":"api","kind":"function"},{"id":"api_persistent!","name":"persistent!","signatures":["(persistent! coll)"],"desc":"Converts a transient collection back to a persistent collection.\n   Alias for `persistent`, matching Clojure's `persistent!` naming.","anchor":"persistent-1","type":"api","kind":"function"},{"id":"api_phel->php","name":"phel->php","signatures":["(phel->php x)"],"desc":"Recursively converts a Phel data structure to a PHP array.","anchor":"phel-php","type":"api","kind":"function"},{"id":"api_php->phel","name":"php->phel","signatures":["(php->phel x)"],"desc":"Recursively converts a PHP array to Phel data structures.\n\n  Indexed PHP arrays become vectors, associative PHP arrays become maps.","anchor":"php-phel","type":"api","kind":"function"},{"id":"api_php-array-to-map","name":"php-array-to-map","signatures":["(php-array-to-map arr)"],"desc":"Converts a PHP Array to a Phel map.","anchor":"php-array-to-map","type":"api","kind":"function"},{"id":"api_php-array?","name":"php-array?","signatures":["(php-array? x)"],"desc":"Returns true if `x` is a PHP Array, false otherwise.","anchor":"php-array","type":"api","kind":"function"},{"id":"api_php-associative-array","name":"php-associative-array","signatures":["(php-associative-array & xs)"],"desc":"Creates a PHP associative array from key-value pairs.\n\n  Arguments:\n    Key-value pairs (must be even number of arguments)","anchor":"php-associative-array","type":"api","kind":"function"},{"id":"api_php-indexed-array","name":"php-indexed-array","signatures":["(php-indexed-array & xs)"],"desc":"Creates a PHP indexed array from the given values.","anchor":"php-indexed-array","type":"api","kind":"function"},{"id":"api_php-object?","name":"php-object?","signatures":["(php-object? x)"],"desc":"Returns true if `x` is a PHP object, false otherwise.","anchor":"php-object","type":"api","kind":"function"},{"id":"api_php-resource?","name":"php-resource?","signatures":["(php-resource? x)"],"desc":"Returns true if `x` is a PHP resource, false otherwise.","anchor":"php-resource","type":"api","kind":"function"},{"id":"api_pop","name":"pop","signatures":["(pop coll)"],"desc":"Removes the last element of the array `coll`. If the array is empty returns nil.","anchor":"pop","type":"api","kind":"function"},{"id":"api_pop!","name":"pop!","signatures":["(pop! tcoll)"],"desc":"Removes the last element from a transient vector, mutating it in place.\n   Raises `InvalidArgumentException` when `tcoll` is not a transient vector.\n   Matches Clojure's `pop!` semantics.","anchor":"pop-1","type":"api","kind":"function"},{"id":"api_pos?","name":"pos?","signatures":["(pos? x)"],"desc":"Checks if `x` is greater than zero.","anchor":"pos","type":"api","kind":"function"},{"id":"api_print","name":"print","signatures":["(print & xs)"],"desc":"Prints the given values to the default output stream. Returns nil.","anchor":"print","type":"api","kind":"function"},{"id":"api_print-str","name":"print-str","signatures":["(print-str & xs)"],"desc":"Same as print. But instead of writing it to an output stream, the resulting string is returned.","anchor":"print-str","type":"api","kind":"function"},{"id":"api_printf","name":"printf","signatures":["(printf fmt & xs)"],"desc":"Output a formatted string. See PHP's <i>printf<\/i> for more information.","anchor":"printf","type":"api","kind":"function"},{"id":"api_println","name":"println","signatures":["(println & xs)"],"desc":"Same as print followed by a newline.","anchor":"println","type":"api","kind":"function"},{"id":"api_protocol-type-key","name":"protocol-type-key","signatures":["(protocol-type-key x)"],"desc":"Returns the dispatch key for protocol dispatch. Returns a type keyword\n  for primitive types, or the PHP class name string for objects\/structs.\n\n  Optimized to avoid the full `type` cond chain: checks scalars first\n  (most common in tight loops), then objects.","anchor":"protocol-type-key","type":"api","kind":"function"},{"id":"api_push","name":"push","signatures":["(push coll x)"],"desc":"Inserts `x` at the end of the sequence `coll`.","anchor":"push","type":"api","kind":"function"},{"id":"api_put","name":"put","signatures":["(put ds key value)"],"desc":"Puts `value` mapped to `key` on the datastructure `ds`. Returns `ds`.","anchor":"put","type":"api","kind":"function"},{"id":"api_put-in","name":"put-in","signatures":["(put-in ds ks v)"],"desc":"Puts a value into a nested data structure.","anchor":"put-in","type":"api","kind":"function"},{"id":"api_quote","name":"quote","signatures":["(quote form)"],"desc":"Returns the unevaluated form.","anchor":"quote","type":"api","kind":"function"},{"id":"api_rand","name":"rand","signatures":["(rand)"],"desc":"Returns a random number between 0 and 1.","anchor":"rand","type":"api","kind":"function"},{"id":"api_rand-int","name":"rand-int","signatures":["(rand-int n)"],"desc":"Returns a random number between 0 and `n`.","anchor":"rand-int","type":"api","kind":"function"},{"id":"api_rand-nth","name":"rand-nth","signatures":["(rand-nth xs)"],"desc":"Returns a random item from xs.","anchor":"rand-nth","type":"api","kind":"function"},{"id":"api_random-uuid","name":"random-uuid","signatures":["(random-uuid)"],"desc":"Returns a random UUID v4 string.","anchor":"random-uuid","type":"api","kind":"function"},{"id":"api_range","name":"range","signatures":["(range & args)"],"desc":"Creates a lazy sequence of numbers. With no arguments returns an infinite\n  sequence starting at 0. With one argument returns (0..n). With two (start..end).\n  With three (start..end step). Note: the infinite sequence is bounded by PHP_INT_MAX.","anchor":"range","type":"api","kind":"function"},{"id":"api_re-find","name":"re-find","signatures":["(re-find re s)"],"desc":"Returns the first match of pattern in string, or nil if no match.\n  If the pattern has groups, returns a vector of [full-match group1 group2 ...].","anchor":"re-find","type":"api","kind":"function"},{"id":"api_re-matches","name":"re-matches","signatures":["(re-matches re s)"],"desc":"Returns the match, if any, of string to pattern. If the pattern has groups,\n  returns a vector of [full-match group1 group2 ...]. Returns nil if no match.\n  Unlike re-find, the entire string must match.","anchor":"re-matches","type":"api","kind":"function"},{"id":"api_re-pattern","name":"re-pattern","signatures":["(re-pattern s)"],"desc":"Returns a PCRE pattern string from `s`. If `s` is already delimited,\n  returns it as-is. Otherwise wraps in `\/` delimiters.","anchor":"re-pattern","type":"api","kind":"function"},{"id":"api_re-seq","name":"re-seq","signatures":["(re-seq re s)"],"desc":"Returns a sequence of successive matches of pattern in string.","anchor":"re-seq","type":"api","kind":"function"},{"id":"api_read-file-lazy","name":"read-file-lazy","signatures":["(read-file-lazy filename)","(read-file-lazy filename chunk-size)"],"desc":"Returns a lazy sequence of byte chunks from a file.","anchor":"read-file-lazy","type":"api","kind":"function"},{"id":"api_read-string","name":"read-string","signatures":["(read-string s)"],"desc":"Reads the first phel expression from the string s.","anchor":"read-string","type":"api","kind":"function"},{"id":"api_realized?","name":"realized?","signatures":["(realized? coll)"],"desc":"Returns true if a lazy sequence, delay, or future has been realized, false otherwise.","anchor":"realized","type":"api","kind":"function"},{"id":"api_recur","name":"recur","signatures":["(recur expr*)"],"desc":"Internally recur is implemented as a PHP while loop and therefore prevents the Maximum function nesting level errors.","anchor":"recur","type":"api","kind":"function"},{"id":"api_reduce","name":"reduce","signatures":["(reduce f & args)"],"desc":"Reduces collection to a single value by repeatedly applying function to accumulator and elements.\n  Respects early termination via `(reduced val)`.","anchor":"reduce","type":"api","kind":"function"},{"id":"api_reduced","name":"reduced","signatures":["(reduced x)"],"desc":"Wraps `x` in a Reduced, signaling early termination from reduce\/transduce.","anchor":"reduced","type":"api","kind":"function"},{"id":"api_reduced?","name":"reduced?","signatures":["(reduced? x)"],"desc":"Returns true if `x` is a Reduced value.","anchor":"reduced-1","type":"api","kind":"function"},{"id":"api_reify","name":"reify","signatures":["(reify & specs)"],"desc":"Creates an anonymous object implementing one or more protocols.\n  Method bodies close over local bindings. Each instance carries its\n  own captured state, so reify works correctly inside loops.\n\n  Syntax:\n    (reify\n      ProtocolName\n      (method-name [this arg1] body)\n      AnotherProtocol\n      (another-method [this] body))","anchor":"reify","type":"api","kind":"macro"},{"id":"api_remove","name":"remove","signatures":["(remove pred & args)"],"desc":"Returns a lazy sequence of elements where predicate returns false.\n   Opposite of filter. When called with pred only, returns a transducer.","anchor":"remove","type":"api","kind":"function"},{"id":"api_remove-watch","name":"remove-watch","signatures":["(remove-watch variable key)"],"desc":"Removes a watch function from a variable by key.","anchor":"remove-watch","type":"api","kind":"function"},{"id":"api_rename-keys","name":"rename-keys","signatures":["(rename-keys m kmap)"],"desc":"Returns the map with keys renamed according to kmap.\n  Keys not present in kmap are left unchanged.","anchor":"rename-keys","type":"api","kind":"function"},{"id":"api_repeat","name":"repeat","signatures":["(repeat a & rest)"],"desc":"Returns a vector of length n where every element is x.\n\n  With one argument returns an infinite lazy sequence of x.","anchor":"repeat","type":"api","kind":"function"},{"id":"api_repeatedly","name":"repeatedly","signatures":["(repeatedly a & rest)"],"desc":"Returns a vector of length n with values produced by repeatedly calling f.\n\n  With one argument returns an infinite lazy sequence of calls to f.","anchor":"repeatedly","type":"api","kind":"function"},{"id":"api_reset!","name":"reset!","signatures":["(reset! variable value)"],"desc":"Sets a new value on the given atom. Returns the new value.","anchor":"reset","type":"api","kind":"function"},{"id":"api_resolve","name":"resolve","signatures":["(resolve sym)"],"desc":"Resolves the given symbol in the current environment and returns a resolved Symbol with the absolute namespace or nil if it cannot be resolved.","anchor":"resolve","type":"api","kind":"function"},{"id":"api_rest","name":"rest","signatures":["(rest coll)"],"desc":"Returns the sequence after the first element, or empty sequence if none.","anchor":"rest","type":"api","kind":"function"},{"id":"api_reverse","name":"reverse","signatures":["(reverse coll)"],"desc":"Reverses the order of the elements in the given sequence.","anchor":"reverse","type":"api","kind":"function"},{"id":"api_run!","name":"run!","signatures":["(run! f coll)"],"desc":"Calls `(f x)` for each element in `coll` for side effects. Returns nil.","anchor":"run","type":"api","kind":"function"},{"id":"api_satisfies?","name":"satisfies?","signatures":["(satisfies? protocol x)"],"desc":"Returns true if x's type implements all methods of the given protocol.","anchor":"satisfies","type":"api","kind":"function"},{"id":"api_second","name":"second","signatures":["(second coll)"],"desc":"Returns the second element of a sequence, or nil if not present.","anchor":"second","type":"api","kind":"function"},{"id":"api_select-keys","name":"select-keys","signatures":["(select-keys m ks)"],"desc":"Returns a new map including key value pairs from `m` selected with keys `ks`.","anchor":"select-keys","type":"api","kind":"function"},{"id":"api_seq","name":"seq","signatures":["(seq coll)"],"desc":"Returns a seq on the collection. Strings are converted to a vector of characters.\n  Collections are unchanged. Returns nil if coll is empty or nil.\n\n  This function is useful for explicitly converting strings to sequences of characters,\n  enabling sequence operations like map, filter, and frequencies.","anchor":"seq","type":"api","kind":"function"},{"id":"api_seq?","name":"seq?","signatures":["(seq? x)"],"desc":"Returns true if `x` is a seq (implements LazySeqInterface), false otherwise.","anchor":"seq-1","type":"api","kind":"function"},{"id":"api_sequence","name":"sequence","signatures":["(sequence xform coll)"],"desc":"Applies transducer `xform` to `coll`, returning a vector of results.","anchor":"sequence","type":"api","kind":"function"},{"id":"api_set","name":"set","signatures":["(set coll)"],"desc":"Coerces a collection to a set. Returns a set containing the distinct elements of `coll`.\n  For creating sets from arguments, use `hash-set`.","anchor":"set","type":"api","kind":"function"},{"id":"api_set!","name":"set!","signatures":["(set! variable value)"],"desc":"Sets a new value to the given variable.","anchor":"set-1","type":"api","kind":"function"},{"id":"api_set-meta!","name":"set-meta!","signatures":[],"desc":"Sets the metadata to a given object.","anchor":"set-meta","type":"api","kind":"function"},{"id":"api_set-validator!","name":"set-validator!","signatures":["(set-validator! variable f)"],"desc":"Sets a validator function on a variable. The validator is called before any\n  state change with the proposed new value. If it returns a falsy value, an\n  exception is thrown and the state is not changed. Pass nil to remove.","anchor":"set-validator","type":"api","kind":"function"},{"id":"api_set-var","name":"set-var","signatures":["(var value)"],"desc":"Variables provide a way to manage mutable state that can be updated with `set!` and `swap!`. Each variable contains a single value. To create a variable use the var function.","anchor":"set-var","type":"api","kind":"function"},{"id":"api_set?","name":"set?","signatures":["(set? x)"],"desc":"Returns true if `x` is a set, false otherwise.","anchor":"set-2","type":"api","kind":"function"},{"id":"api_shuffle","name":"shuffle","signatures":["(shuffle coll)"],"desc":"Returns a random permutation of coll.","anchor":"shuffle","type":"api","kind":"function"},{"id":"api_slice","name":"slice","signatures":["(slice coll & [offset & [length]])"],"desc":"Extracts a slice of `coll` starting at `offset` with optional `length`.","anchor":"slice","type":"api","kind":"function"},{"id":"api_slurp","name":"slurp","signatures":["(slurp path & [opts])"],"desc":"Reads entire file or URL into a string.","anchor":"slurp","type":"api","kind":"function"},{"id":"api_some","name":"some","signatures":["(some pred coll)"],"desc":"Returns the first truthy value of applying predicate to elements, or nil if none found.","anchor":"some","type":"api","kind":"function"},{"id":"api_some->","name":"some->","signatures":["(some-> x & forms)"],"desc":"Threads `x` through the forms like `->` but stops when a form returns `nil`.","anchor":"some-1","type":"api","kind":"macro"},{"id":"api_some->>","name":"some->>","signatures":["(some->> x & forms)"],"desc":"Threads `x` through the forms like `->>` but stops when a form returns `nil`.","anchor":"some-2","type":"api","kind":"macro"},{"id":"api_some-fn","name":"some-fn","signatures":["(some-fn p & ps)"],"desc":"Takes a variadic set of predicates and returns a function `f` that,\n   when called with any number of arguments, returns the first logical\n   true value produced by applying any of the composing predicates to\n   any of its arguments, and `nil` otherwise. The returned function\n   short-circuits on the first truthy result: arguments after it are\n   not inspected, and predicates after it are not tried.\n   Predicates are consulted in the order supplied; for a given\n   predicate, arguments are consulted left-to-right. Matches Clojure's\n   `some-fn` semantics.","anchor":"some-fn","type":"api","kind":"function"},{"id":"api_some?","name":"some?","signatures":["(some? x)","(some? pred coll)"],"desc":"With 1 arg, returns true if `x` is not nil (Clojure semantics).\n   With 2 args, returns true if `pred` is true for at least one element in `coll`.","anchor":"some-3","type":"api","kind":"function"},{"id":"api_sort","name":"sort","signatures":["(sort coll & [comp])"],"desc":"Returns a sorted vector. If no comparator is supplied compare is used.","anchor":"sort","type":"api","kind":"function"},{"id":"api_sort-by","name":"sort-by","signatures":["(sort-by keyfn coll & [comp])"],"desc":"Returns a sorted vector where the sort order is determined by comparing `(keyfn item)`.\n\n  If no comparator is supplied compare is used.","anchor":"sort-by","type":"api","kind":"function"},{"id":"api_sorted-map","name":"sorted-map","signatures":["(sorted-map & xs)"],"desc":"Creates a new sorted map. Keys are in natural sorted order.\n  The number of parameters must be even.","anchor":"sorted-map","type":"api","kind":"function"},{"id":"api_sorted-map-by","name":"sorted-map-by","signatures":["(sorted-map-by comp & xs)"],"desc":"Creates a new sorted map using the given comparator for key ordering.\n  The comparator takes two arguments and returns a negative integer,\n  zero, or a positive integer.","anchor":"sorted-map-by","type":"api","kind":"function"},{"id":"api_sorted-set","name":"sorted-set","signatures":["(sorted-set & xs)"],"desc":"Creates a new sorted set. Elements are in natural sorted order.","anchor":"sorted-set","type":"api","kind":"function"},{"id":"api_sorted-set-by","name":"sorted-set-by","signatures":["(sorted-set-by comp & xs)"],"desc":"Creates a new sorted set using the given comparator for element ordering.","anchor":"sorted-set-by","type":"api","kind":"function"},{"id":"api_sorted?","name":"sorted?","signatures":["(sorted? coll)"],"desc":"Returns true if `coll` is a sorted collection (sorted-map or sorted-set), false otherwise.","anchor":"sorted","type":"api","kind":"function"},{"id":"api_spit","name":"spit","signatures":["(spit filename data & [opts])"],"desc":"Writes data to file, returning number of bytest that were written or `nil`\n  on failure. Accepts `opts` map for overriding default PHP file_put_contents\n  arguments, as example to append to file use `{:flags php\/FILE_APPEND}`.\n\n  See PHP's <i>file_put_contents<\/i> for more information.","anchor":"spit","type":"api","kind":"function"},{"id":"api_split-at","name":"split-at","signatures":["(split-at n coll)"],"desc":"Returns a vector of `[(take n coll) (drop n coll)]`.","anchor":"split-at","type":"api","kind":"function"},{"id":"api_split-with","name":"split-with","signatures":["(split-with f coll)"],"desc":"Returns a vector of `[(take-while pred coll) (drop-while pred coll)]`.","anchor":"split-with","type":"api","kind":"function"},{"id":"api_str","name":"str","signatures":["(str & args)"],"desc":"Creates a string by concatenating values together. If no arguments are\nprovided an empty string is returned. Nil is represented as an empty string.\nBooleans are represented as \"true\" or \"false\" (matching Clojure semantics).\nOtherwise, it tries to call `__toString`.","anchor":"str","type":"api","kind":"function"},{"id":"api_str-contains?","name":"str-contains?","signatures":["(str-contains? str s)"],"desc":"Returns true if str contains s.","anchor":"str-contains","type":"api","kind":"function"},{"id":"api_string?","name":"string?","signatures":["(string? x)"],"desc":"Returns true if `x` is a string, false otherwise.","anchor":"string","type":"api","kind":"function"},{"id":"api_struct?","name":"struct?","signatures":["(struct? x)"],"desc":"Returns true if `x` is a struct, false otherwise.","anchor":"struct","type":"api","kind":"function"},{"id":"api_subset?","name":"subset?","signatures":["(subset? s1 s2)"],"desc":"Returns true if `s1` is a subset of `s2`, i.e. every element in `s1` is also in `s2`.","anchor":"subset","type":"api","kind":"function"},{"id":"api_sum","name":"sum","signatures":["(sum xs)"],"desc":"Returns the sum of all elements is `xs`.","anchor":"sum","type":"api","kind":"function"},{"id":"api_superset?","name":"superset?","signatures":["(superset? s1 s2)"],"desc":"Returns true if `s1` is a superset of `s2`, i.e. every element in `s2` is also in `s1`.","anchor":"superset","type":"api","kind":"function"},{"id":"api_swap!","name":"swap!","signatures":["(swap! variable f & args)"],"desc":"Atomically swaps the value of the atom to `(apply f current-value args)`.\n\n  Returns the new value after the swap.","anchor":"swap","type":"api","kind":"function"},{"id":"api_symbol","name":"symbol","signatures":["(symbol name-or-ns & [name])"],"desc":"Returns a new symbol for given string with optional namespace.\n\n  With one argument, creates a symbol without namespace.\n  With two arguments, creates a symbol in the given namespace.","anchor":"symbol","type":"api","kind":"function"},{"id":"api_symbol?","name":"symbol?","signatures":["(symbol? x)"],"desc":"Returns true if `x` is a symbol, false otherwise.","anchor":"symbol-1","type":"api","kind":"function"},{"id":"api_symmetric-difference","name":"symmetric-difference","signatures":["(symmetric-difference set & sets)"],"desc":"Symmetric difference between multiple sets into a new one.","anchor":"symmetric-difference","type":"api","kind":"function"},{"id":"api_take","name":"take","signatures":["(take n & args)"],"desc":"Takes the first `n` elements of `coll`.\n  When called with n only, returns a transducer.","anchor":"take","type":"api","kind":"function"},{"id":"api_take-last","name":"take-last","signatures":["(take-last n coll)"],"desc":"Takes the last `n` elements of `coll`.","anchor":"take-last","type":"api","kind":"function"},{"id":"api_take-nth","name":"take-nth","signatures":["(take-nth n & args)"],"desc":"Returns every nth item in `coll`. Returns a lazy sequence.\n  When called with n only, returns a transducer.","anchor":"take-nth","type":"api","kind":"function"},{"id":"api_take-while","name":"take-while","signatures":["(take-while pred & args)"],"desc":"Takes all elements at the front of `coll` where `(pred x)` is true. Returns a lazy sequence.\n  When called with pred only, returns a transducer.","anchor":"take-while","type":"api","kind":"function"},{"id":"api_throw","name":"throw","signatures":["(throw exception)"],"desc":"Throw an exception.","anchor":"throw","type":"api","kind":"function"},{"id":"api_time","name":"time","signatures":["(time expr)"],"desc":"Evaluates expr and prints the time it took. Returns the value of expr.","anchor":"time","type":"api","kind":"macro"},{"id":"api_to-array","name":"to-array","signatures":["(to-array coll)"],"desc":"Returns a PHP array containing the elements of `coll`. Accepts any\n  collection (vector, list, set, map, PHP array) or `nil`, which yields\n  an empty PHP array. Matches Clojure's `to-array` for `.cljc` interop \u2014\n  in Phel the result is a plain PHP array since PHP has no `Object[]`.","anchor":"to-array","type":"api","kind":"function"},{"id":"api_to-php-array","name":"to-php-array","signatures":[],"desc":"Creates a PHP Array from a sequential data structure.","anchor":"to-php-array","type":"api","kind":"function"},{"id":"api_transduce","name":"transduce","signatures":["(transduce xform f & args)"],"desc":"Reduce with a transformation of `f` (xf). If init is not supplied,\n  `(f)` will be called to produce it. `f` should be a reducing function\n  that returns the initial value when called with no arguments.","anchor":"transduce","type":"api","kind":"function"},{"id":"api_transient","name":"transient","signatures":["(transient coll)"],"desc":"Converts a persistent collection to a transient collection for efficient updates.\n\n  Transient collections provide faster performance for multiple sequential updates.\n  Use `persistent` to convert back.","anchor":"transient","type":"api","kind":"function"},{"id":"api_tree-seq","name":"tree-seq","signatures":["(tree-seq branch? children root)"],"desc":"Returns a vector of the nodes in the tree, via a depth-first walk.\n  branch? is a function with one argument that returns true if the given node\n  has children.\n  children must be a function with one argument that returns the children of the node.\n  root the root node of the tree.","anchor":"tree-seq","type":"api","kind":"function"},{"id":"api_true?","name":"true?","signatures":["(true? x)"],"desc":"Checks if value is exactly true (not just truthy).","anchor":"true","type":"api","kind":"function"},{"id":"api_truthy?","name":"truthy?","signatures":["(truthy? x)"],"desc":"Checks if `x` is truthy. Same as `x == true` in PHP.","anchor":"truthy","type":"api","kind":"function"},{"id":"api_try","name":"try","signatures":["(try expr* catch-clause* finally-clause?)"],"desc":"All expressions are evaluated and if no exception is thrown the value of the last expression is returned. If an exception occurs and a matching catch-clause is provided, its expression is evaluated and the value is returned. If no matching catch-clause can be found the exception is propagated out of the function. Before returning normally or abnormally the optionally finally-clause is evaluated.","anchor":"try","type":"api","kind":"function"},{"id":"api_type","name":"type","signatures":["(type x)"],"desc":"Returns the type of `x`. The following types can be returned:\n\n* `:vector`\n* `:list`\n* `:struct`\n* `:hash-map`\n* `:set`\n* `:keyword`\n* `:symbol`\n* `:var`\n* `:int`\n* `:float`\n* `:string`\n* `:nil`\n* `:boolean`\n* `:function`\n* `:php\/array`\n* `:php\/resource`\n* `:php\/object`\n* `:unknown`","anchor":"type","type":"api","kind":"function"},{"id":"api_underive","name":"underive","signatures":["(underive child parent)"],"desc":"Removes a parent\/child relationship from the global hierarchy.","anchor":"underive","type":"api","kind":"function"},{"id":"api_union","name":"union","signatures":["(union & sets)"],"desc":"Union multiple sets into a new one.","anchor":"union","type":"api","kind":"function"},{"id":"api_unquote","name":"unquote","signatures":["(unquote expr)"],"desc":"Values that should be evaluated in a macro are marked with the unquote function. Shortcut: ,","anchor":"unquote","type":"api","kind":"function"},{"id":"api_unquote-splicing","name":"unquote-splicing","signatures":["(unquote-splicing expr)"],"desc":"Values that should be evaluated in a macro are marked with the unquote function. Shortcut: ,@","anchor":"unquote-splicing","type":"api","kind":"function"},{"id":"api_unreduced","name":"unreduced","signatures":["(unreduced x)"],"desc":"If `x` is Reduced, returns the unwrapped value; otherwise returns `x`.","anchor":"unreduced","type":"api","kind":"function"},{"id":"api_unset","name":"unset","signatures":["(unset ds key)"],"desc":"Returns `ds` without `key`.","anchor":"unset","type":"api","kind":"function"},{"id":"api_unset-in","name":"unset-in","signatures":["(unset-in ds ks)"],"desc":"Removes a value from a nested data structure.","anchor":"unset-in","type":"api","kind":"function"},{"id":"api_update","name":"update","signatures":["(update ds k f & args)"],"desc":"Updates a value in a datastructure by applying `f` to the current value.","anchor":"update","type":"api","kind":"function"},{"id":"api_update-in","name":"update-in","signatures":["(update-in ds [k & ks] f & args)"],"desc":"Updates a value in a nested data structure by applying `f` to the value at path.","anchor":"update-in","type":"api","kind":"function"},{"id":"api_update-keys","name":"update-keys","signatures":["(update-keys m f)"],"desc":"Returns a map with `f` applied to each key.","anchor":"update-keys","type":"api","kind":"function"},{"id":"api_update-vals","name":"update-vals","signatures":["(update-vals m f)"],"desc":"Returns a map with `f` applied to each value.","anchor":"update-vals","type":"api","kind":"function"},{"id":"api_vals","name":"vals","signatures":["(vals coll)"],"desc":"Returns a sequence of all values in a map.","anchor":"vals","type":"api","kind":"function"},{"id":"api_values","name":"values","signatures":["(values coll)"],"desc":"Returns a sequence of all values in a map.","anchor":"values","type":"api","kind":"function"},{"id":"api_var","name":"var","signatures":["(var value)"],"desc":"Creates a new variable with the given value.","anchor":"var","type":"api","kind":"function"},{"id":"api_var?","name":"var?","signatures":["(var? x)"],"desc":"Checks if the given value is a variable.","anchor":"var-1","type":"api","kind":"function"},{"id":"api_vary-meta","name":"vary-meta","signatures":[],"desc":"Returns an object with (apply f (meta obj) args) as its new metadata.","anchor":"vary-meta","type":"api","kind":"function"},{"id":"api_vec","name":"vec","signatures":["(vec coll)"],"desc":"Coerces a collection to a vector. For hash-maps and structs, entries\n  are returned as 2-element `[key value]` vectors, matching Clojure.","anchor":"vec","type":"api","kind":"function"},{"id":"api_vector","name":"vector","signatures":["(vector & xs)"],"desc":"Creates a new vector. If no argument is provided, an empty vector is created.","anchor":"vector","type":"api","kind":"function"},{"id":"api_vector?","name":"vector?","signatures":["(vector? x)"],"desc":"Returns true if `x` is a vector, false otherwise.","anchor":"vector-1","type":"api","kind":"function"},{"id":"api_volatile!","name":"volatile!","signatures":["(volatile! val)"],"desc":"Creates a volatile mutable reference with initial value `val`.\n  Use for transducer state that needs fast mutation without watches.","anchor":"volatile","type":"api","kind":"function"},{"id":"api_volatile?","name":"volatile?","signatures":["(volatile? x)"],"desc":"Returns true if `x` is a Volatile.","anchor":"volatile-1","type":"api","kind":"function"},{"id":"api_vreset!","name":"vreset!","signatures":["(vreset! vol val)"],"desc":"Sets the value of volatile `vol` to `val`. Returns `val`.","anchor":"vreset","type":"api","kind":"function"},{"id":"api_vswap!","name":"vswap!","signatures":["(vswap! vol f & args)"],"desc":"Applies `f` to the current value of volatile `vol` plus `args`,\n  and sets the new value. Returns the new value.","anchor":"vswap","type":"api","kind":"function"},{"id":"api_when","name":"when","signatures":["(when test & body)"],"desc":"Evaluates body if test is true, otherwise returns nil.","anchor":"when","type":"api","kind":"macro"},{"id":"api_when-first","name":"when-first","signatures":["(when-first bindings & body)"],"desc":"Binds name to the first element of coll. When the collection is non-empty\n  (first returns non-nil), evaluates body with the binding.","anchor":"when-first","type":"api","kind":"macro"},{"id":"api_when-let","name":"when-let","signatures":["(when-let bindings & body)"],"desc":"When test is true, evaluates body with binding-form bound to the value of test","anchor":"when-let","type":"api","kind":"macro"},{"id":"api_when-not","name":"when-not","signatures":["(when-not test & body)"],"desc":"Evaluates body if test is false, otherwise returns nil.","anchor":"when-not","type":"api","kind":"macro"},{"id":"api_when-some","name":"when-some","signatures":["(when-some bindings & body)"],"desc":"Binds name to the value of test. When test is not nil, evaluates body with\n  binding-form bound to the value of test. Unlike when-let, false and 0 are not\n  treated as falsy \u2014 only nil causes the body to be skipped.","anchor":"when-some","type":"api","kind":"macro"},{"id":"api_with-meta","name":"with-meta","signatures":[],"desc":"Returns `obj` with the given metadata `meta` attached.","anchor":"with-meta","type":"api","kind":"function"},{"id":"api_with-output-buffer","name":"with-output-buffer","signatures":["(with-output-buffer & body)"],"desc":"Everything that is printed inside the body will be stored in a buffer.\n   The result of the buffer is returned.","anchor":"with-output-buffer","type":"api","kind":"macro"},{"id":"api_zero?","name":"zero?","signatures":["(zero? x)"],"desc":"Checks if `x` is zero.","anchor":"zero","type":"api","kind":"function"},{"id":"api_zipcoll","name":"zipcoll","signatures":["(zipcoll a b)"],"desc":"Creates a map from two sequential data structures. Returns a new map.","anchor":"zipcoll","type":"api","kind":"function"},{"id":"api_zipmap","name":"zipmap","signatures":["(zipmap keys vals)"],"desc":"Returns a new map with the keys mapped to the corresponding values.\n\n  Stops when the shorter of `keys` or `vals` is exhausted.\n  Works safely with infinite lazy sequences.","anchor":"zipmap","type":"api","kind":"function"},{"id":"api_add-tap","name":"debug\/add-tap","signatures":["(add-tap f)"],"desc":"Register a global tap handler function.","anchor":"debug-add-tap","type":"api","kind":"function"},{"id":"api_dbg","name":"debug\/dbg","signatures":["(dbg expr)"],"desc":"Evaluates an expression and prints it with its result.","anchor":"debug-dbg","type":"api","kind":"macro"},{"id":"api_dotrace","name":"debug\/dotrace","signatures":["(dotrace name f)"],"desc":"Wraps a function to print each call and result with indentation.","anchor":"debug-dotrace","type":"api","kind":"function"},{"id":"api_remove-tap","name":"debug\/remove-tap","signatures":["(remove-tap f)"],"desc":"Unregister a global tap handler function.","anchor":"debug-remove-tap","type":"api","kind":"function"},{"id":"api_reset-taps!","name":"debug\/reset-taps!","signatures":["(reset-taps!)"],"desc":"Clear all tap handlers.","anchor":"debug-reset-taps","type":"api","kind":"function"},{"id":"api_reset-trace-state!","name":"debug\/reset-trace-state!","signatures":["(reset-trace-state!)"],"desc":"Resets trace counters to initial values.","anchor":"debug-reset-trace-state","type":"api","kind":"function"},{"id":"api_set-trace-id-padding!","name":"debug\/set-trace-id-padding!","signatures":["(set-trace-id-padding! estimated-id-padding)"],"desc":"Sets the number of digits for trace ID padding.","anchor":"debug-set-trace-id-padding","type":"api","kind":"function"},{"id":"api_spy","name":"debug\/spy","signatures":["(spy expr)","(spy label expr)"],"desc":"Evaluates an expression and prints it with an optional label.","anchor":"debug-spy","type":"api","kind":"macro"},{"id":"api_tap","name":"debug\/tap","signatures":["(tap value)","(tap value handler)"],"desc":"Prints a value and returns it unchanged. Useful in pipelines.","anchor":"debug-tap","type":"api","kind":"function"},{"id":"api_tap>","name":"debug\/tap>","signatures":["(tap> value)"],"desc":"Send a value to all registered tap handlers.","anchor":"tap-1","type":"api","kind":"function"},{"id":"api_doctype","name":"html\/doctype","signatures":["(doctype type)"],"desc":"Returns an HTML doctype declaration.","anchor":"html-doctype","type":"api","kind":"function"},{"id":"api_escape-html","name":"html\/escape-html","signatures":["(escape-html s)"],"desc":"Escapes HTML special characters to prevent XSS.","anchor":"html-escape-html","type":"api","kind":"function"},{"id":"api_html","name":"html\/html","signatures":["(html & content)"],"desc":"Compiles Phel vectors to HTML strings.","anchor":"html-html","type":"api","kind":"macro"},{"id":"api_raw-string","name":"html\/raw-string","signatures":["(raw-string s)"],"desc":"Creates a new raw-string struct.","anchor":"html-raw-string","type":"api","kind":"function"},{"id":"api_raw-string?","name":"html\/raw-string?","signatures":["(raw-string? x)"],"desc":"Checks if `x` is an instance of the raw-string struct.","anchor":"raw-string-1","type":"api","kind":"function"},{"id":"api_create-response-from-map","name":"http\/create-response-from-map","signatures":[],"desc":"","anchor":"http-create-response-from-map","type":"api","kind":"function"},{"id":"api_create-response-from-string","name":"http\/create-response-from-string","signatures":[],"desc":"","anchor":"http-create-response-from-string","type":"api","kind":"function"},{"id":"api_emit-response","name":"http\/emit-response","signatures":["(emit-response response)"],"desc":"Emits the response by sending headers and outputting the body.","anchor":"http-emit-response","type":"api","kind":"function"},{"id":"api_files-from-globals","name":"http\/files-from-globals","signatures":["(files-from-globals & [files])"],"desc":"Extracts the files from `$_FILES` and normalizes them to a map of \"uploaded-file\".","anchor":"http-files-from-globals","type":"api","kind":"function"},{"id":"api_headers-from-server","name":"http\/headers-from-server","signatures":["(headers-from-server & [server])"],"desc":"Extracts all headers from the `$_SERVER` variable.","anchor":"http-headers-from-server","type":"api","kind":"function"},{"id":"api_request","name":"http\/request","signatures":["(request method uri headers parsed-body query-params cookie-params server-params uploaded-files version attributes)"],"desc":"Creates a new request struct.","anchor":"http-request","type":"api","kind":"function"},{"id":"api_request-from-globals","name":"http\/request-from-globals","signatures":["(request-from-globals)"],"desc":"Extracts a request from `$_SERVER`, `$_GET`, `$_POST`, `$_COOKIE` and `$_FILES`.","anchor":"http-request-from-globals","type":"api","kind":"function"},{"id":"api_request-from-globals-args","name":"http\/request-from-globals-args","signatures":["(request-from-globals-args server get-parameter post-parameter cookies files)"],"desc":"Extracts a request from args.","anchor":"http-request-from-globals-args","type":"api","kind":"function"},{"id":"api_request-from-map","name":"http\/request-from-map","signatures":["(request-from-map {:method method, :version version, :uri uri, :headers headers, :parsed-body parsed-body, :query-params query-params, :cookie-params cookie-params, :server-params server-params, :uploaded-files uploaded-files, :attributes attributes})"],"desc":"Creates a request struct from a map with optional keys :method, :uri, :headers, etc.","anchor":"http-request-from-map","type":"api","kind":"function"},{"id":"api_request?","name":"http\/request?","signatures":["(request? x)"],"desc":"Checks if `x` is an instance of the request struct.","anchor":"request-1","type":"api","kind":"function"},{"id":"api_response","name":"http\/response","signatures":["(response status headers body version reason)"],"desc":"Creates a new response struct.","anchor":"http-response","type":"api","kind":"function"},{"id":"api_response-from-map","name":"http\/response-from-map","signatures":["(response-from-map {:status status, :headers headers, :body body, :version version, :reason reason})"],"desc":"Creates a response struct from a map with optional keys :status, :headers, :body, :version, and :reason.","anchor":"http-response-from-map","type":"api","kind":"function"},{"id":"api_response-from-string","name":"http\/response-from-string","signatures":["(response-from-string s)"],"desc":"Create a response from a string.","anchor":"http-response-from-string","type":"api","kind":"function"},{"id":"api_response?","name":"http\/response?","signatures":["(response? x)"],"desc":"Checks if `x` is an instance of the response struct.","anchor":"response-1","type":"api","kind":"function"},{"id":"api_uploaded-file","name":"http\/uploaded-file","signatures":["(uploaded-file tmp-file size error-status client-filename client-media-type)"],"desc":"Creates a new uploaded-file struct.","anchor":"http-uploaded-file","type":"api","kind":"function"},{"id":"api_uploaded-file?","name":"http\/uploaded-file?","signatures":["(uploaded-file? x)"],"desc":"Checks if `x` is an instance of the uploaded-file struct.","anchor":"uploaded-file-1","type":"api","kind":"function"},{"id":"api_uri","name":"http\/uri","signatures":["(uri scheme userinfo host port path query fragment)"],"desc":"Creates a new uri struct.","anchor":"http-uri","type":"api","kind":"function"},{"id":"api_uri-from-globals","name":"http\/uri-from-globals","signatures":["(uri-from-globals & [server])"],"desc":"Extracts the URI from the `$_SERVER` variable.","anchor":"http-uri-from-globals","type":"api","kind":"function"},{"id":"api_uri-from-string","name":"http\/uri-from-string","signatures":["(uri-from-string url)"],"desc":"Create a uri struct from a string.","anchor":"http-uri-from-string","type":"api","kind":"function"},{"id":"api_uri?","name":"http\/uri?","signatures":["(uri? x)"],"desc":"Checks if `x` is an instance of the uri struct.","anchor":"uri-1","type":"api","kind":"function"},{"id":"api_decode","name":"json\/decode","signatures":["(decode json & [{:flags flags, :depth depth}])"],"desc":"Decodes a JSON string to a Phel value.","anchor":"json-decode","type":"api","kind":"function"},{"id":"api_decode-value","name":"json\/decode-value","signatures":["(decode-value x)"],"desc":"Converts a JSON value to Phel format.","anchor":"json-decode-value","type":"api","kind":"function"},{"id":"api_encode","name":"json\/encode","signatures":["(encode value & [{:flags flags, :depth depth}])"],"desc":"Encodes a Phel value to a JSON string.","anchor":"json-encode","type":"api","kind":"function"},{"id":"api_encode-value","name":"json\/encode-value","signatures":["(encode-value x)"],"desc":"Converts a Phel value to JSON-compatible format.","anchor":"json-encode-value","type":"api","kind":"function"},{"id":"api_valid-key?","name":"json\/valid-key?","signatures":["(valid-key? v)"],"desc":"Checks if a value can be used as a JSON key.","anchor":"json-valid-key","type":"api","kind":"function"},{"id":"api_call-count","name":"mock\/call-count","signatures":["(call-count mock-fn)"],"desc":"Returns the number of times the mock was called.","anchor":"mock-call-count","type":"api","kind":"function"},{"id":"api_called-once?","name":"mock\/called-once?","signatures":["(called-once? mock-fn)"],"desc":"Returns true if the mock was called exactly once.","anchor":"mock-called-once","type":"api","kind":"function"},{"id":"api_called-times?","name":"mock\/called-times?","signatures":["(called-times? mock-fn n)"],"desc":"Returns true if the mock was called exactly n times.","anchor":"mock-called-times","type":"api","kind":"function"},{"id":"api_called-with?","name":"mock\/called-with?","signatures":["(called-with? mock-fn & expected-args)"],"desc":"Returns true if the mock was called with the exact arguments.","anchor":"mock-called-with","type":"api","kind":"function"},{"id":"api_called?","name":"mock\/called?","signatures":["(called? mock-fn)"],"desc":"Returns true if the mock was called at least once.","anchor":"mock-called","type":"api","kind":"function"},{"id":"api_calls","name":"mock\/calls","signatures":["(calls mock-fn)"],"desc":"Returns a list of all argument lists the mock was called with.","anchor":"mock-calls","type":"api","kind":"function"},{"id":"api_clear-all-mocks!","name":"mock\/clear-all-mocks!","signatures":["(clear-all-mocks!)"],"desc":"Clears the entire mock registry.\n  Useful for cleanup between test suites in long-running processes.","anchor":"mock-clear-all-mocks","type":"api","kind":"function"},{"id":"api_first-call","name":"mock\/first-call","signatures":["(first-call mock-fn)"],"desc":"Returns the arguments from the first call.","anchor":"mock-first-call","type":"api","kind":"function"},{"id":"api_last-call","name":"mock\/last-call","signatures":["(last-call mock-fn)"],"desc":"Returns the arguments from the most recent call.","anchor":"mock-last-call","type":"api","kind":"function"},{"id":"api_mock","name":"mock\/mock","signatures":["(mock return-value)"],"desc":"Creates a mock function that returns a fixed value and tracks all calls.","anchor":"mock-mock","type":"api","kind":"function"},{"id":"api_mock-fn","name":"mock\/mock-fn","signatures":["(mock-fn f)"],"desc":"Creates a mock function with custom behavior that tracks all calls.","anchor":"mock-mock-fn","type":"api","kind":"function"},{"id":"api_mock-returning","name":"mock\/mock-returning","signatures":["(mock-returning values)"],"desc":"Creates a mock that returns different values for consecutive calls.\n  After exhausting values, returns the last value.","anchor":"mock-mock-returning","type":"api","kind":"function"},{"id":"api_mock-throwing","name":"mock\/mock-throwing","signatures":["(mock-throwing exception)"],"desc":"Creates a mock that throws an exception when called.","anchor":"mock-mock-throwing","type":"api","kind":"function"},{"id":"api_mock?","name":"mock\/mock?","signatures":["(mock? f)"],"desc":"Returns true if the function is a mock.","anchor":"mock-1","type":"api","kind":"function"},{"id":"api_never-called?","name":"mock\/never-called?","signatures":["(never-called? mock-fn)"],"desc":"Returns true if the mock was never called.","anchor":"mock-never-called","type":"api","kind":"function"},{"id":"api_reset-mock!","name":"mock\/reset-mock!","signatures":["(reset-mock! mock-fn)"],"desc":"Resets the call history of a mock without removing it from the registry.\n  The mock can continue to be used and track new calls.","anchor":"mock-reset-mock","type":"api","kind":"function"},{"id":"api_spy","name":"mock\/spy","signatures":["(spy f)"],"desc":"Wraps an existing function to track calls while preserving original behavior.","anchor":"mock-spy","type":"api","kind":"function"},{"id":"api_with-mock-wrapper","name":"mock\/with-mock-wrapper","signatures":["(with-mock-wrapper bindings & body)"],"desc":"Like with-mocks but for wrapped mocks (interop scenarios).\n  Automatically resets the underlying mock even when wrapped in an adapter function.\n\n  Usage:\n    ```phel\n    (with-mock-wrapper [fn-symbol underlying-mock wrapper-fn]\n      body...)\n    ```\n\n  Multiple wrappers:\n    ```phel\n    (with-mock-wrapper [service-a mock-a (fn [x] (mock-a (inc x)))\n                        service-b mock-b (fn [y] (mock-b (dec y)))]\n      ...)\n    ```","anchor":"mock-with-mock-wrapper","type":"api","kind":"macro"},{"id":"api_with-mocks","name":"mock\/with-mocks","signatures":["(with-mocks bindings & body)"],"desc":"Temporarily replaces functions with mocks using binding.\n  Automatically resets mocks after the body executes.\n\n  Works with inline mock creation:\n    ```phel\n    (with-mocks [http-get (mock {:status 200})]\n      (http-get)\n      ;; Mock is automatically reset after this block)\n    ```\n\n  Also works with pre-defined mocks:\n    ```phel\n    (let [my-mock (mock :result)]\n      (with-mocks [some-fn my-mock]\n        (some-fn)))\n    ```\n\n  If you need to wrap the mock in a function (e.g., to adapt arguments),\n  you'll need to manually reset:\n    ```phel\n    (with-mocks [some-fn (fn [& args] (my-mock (transform args)))]\n      (some-fn)\n      (reset-mock! my-mock))\n    ```","anchor":"mock-with-mocks","type":"api","kind":"macro"},{"id":"api_->","name":"php\/->","signatures":["(php\/-> object call*)","(php\/:: class call*)"],"desc":"Access to an object property or result of chained calls.","anchor":"php","type":"api","kind":"function"},{"id":"api_::","name":"php\/::","signatures":["(php\/:: class (method-name expr*))","(php\/:: class call*)"],"desc":"Calls a static method or property from a PHP class. Both method-name and property must be symbols and cannot be an evaluated value.","anchor":"::-1","type":"api","kind":"function"},{"id":"api_aget","name":"php\/aget","signatures":["(php\/aget arr index)"],"desc":"Equivalent to PHP's `arr[index] ?? null`.","anchor":"php-aget","type":"api","kind":"function"},{"id":"api_aget-in","name":"php\/aget-in","signatures":["(php\/aget-in arr ks)"],"desc":"Equivalent to PHP's `arr[k1][k2][k...] ?? null`.","anchor":"php-aget-in","type":"api","kind":"function"},{"id":"api_apush","name":"php\/apush","signatures":["(php\/apush arr value)"],"desc":"Equivalent to PHP's arr[] = value.","anchor":"php-apush","type":"api","kind":"function"},{"id":"api_apush-in","name":"php\/apush-in","signatures":["(php\/apush-in arr ks value)"],"desc":"Equivalent to PHP's `arr[k1][k2][k...][] = value`.","anchor":"php-apush-in","type":"api","kind":"function"},{"id":"api_aset","name":"php\/aset","signatures":["(php\/aset arr index value)"],"desc":"Equivalent to PHP's `arr[index] = value`.","anchor":"php-aset","type":"api","kind":"function"},{"id":"api_aset-in","name":"php\/aset-in","signatures":["(php\/aset-in arr ks value)"],"desc":"Equivalent to PHP's `arr[k1][k2][k...] = value`.","anchor":"php-aset-in","type":"api","kind":"function"},{"id":"api_aunset","name":"php\/aunset","signatures":["(php\/aunset arr index)"],"desc":"Equivalent to PHP's `unset(arr[index])`.","anchor":"php-aunset","type":"api","kind":"function"},{"id":"api_aunset-in","name":"php\/aunset-in","signatures":["(php\/aunset-in arr ks)"],"desc":"Equivalent to PHP's `unset(arr[k1][k2][k...])`.","anchor":"php-aunset-in","type":"api","kind":"function"},{"id":"api_new","name":"php\/new","signatures":["(php\/new expr args*)"],"desc":"Evaluates expr and creates a new PHP class using the arguments. The instance of the class is returned.","anchor":"php-new","type":"api","kind":"function"},{"id":"api_oset","name":"php\/oset","signatures":["(php\/oset (php\/-> object property) value)","(php\/oset (php\/:: class property) value)"],"desc":"Use `php\/oset` to set a value to a class\/object property.","anchor":"php-oset","type":"api","kind":"function"},{"id":"api_apropos","name":"repl\/apropos","signatures":["(apropos search)"],"desc":"Returns a vector of symbols whose name contains the given search string.\n  Searches across all loaded namespaces.","anchor":"repl-apropos","type":"api","kind":"function"},{"id":"api_build-facade","name":"repl\/build-facade","signatures":[],"desc":"","anchor":"repl-build-facade","type":"api","kind":"function"},{"id":"api_compile-str","name":"repl\/compile-str","signatures":["(compile-str s)"],"desc":"Compiles a Phel expression string to PHP code.","anchor":"repl-compile-str","type":"api","kind":"function"},{"id":"api_dir","name":"repl\/dir","signatures":["(dir ns-str)"],"desc":"Prints all public definitions in the given namespace string.\n\n  Returns nil. Prints one name per line, sorted alphabetically.","anchor":"repl-dir","type":"api","kind":"function"},{"id":"api_doc","name":"repl\/doc","signatures":["(doc sym)"],"desc":"Prints the documentation for the given symbol.","anchor":"repl-doc","type":"api","kind":"macro"},{"id":"api_eval-capturing","name":"repl\/eval-capturing","signatures":["(eval-capturing code-str)"],"desc":"Evaluates a string of Phel code while capturing stdout. Returns a hash-map\n  with :value (the result), :out (captured stdout), :success (boolean), and\n  :error (error message or nil).\n\n  Useful for nREPL and other tooling that needs to separate printed output from\n  return values.","anchor":"repl-eval-capturing","type":"api","kind":"function"},{"id":"api_eval-str","name":"repl\/eval-str","signatures":["(eval-str s)"],"desc":"Evaluates a string of Phel code and returns the result.\n  If the string contains multiple expressions, returns the result of the last one.","anchor":"repl-eval-str","type":"api","kind":"function"},{"id":"api_find-fn","name":"repl\/find-fn","signatures":["(find-fn search)"],"desc":"Searches for functions whose name or docstring contains the search string.\n  Returns a vector of maps with :ns, :name, :doc, :private, :min-arity, :max-arity, :is-variadic.","anchor":"repl-find-fn","type":"api","kind":"function"},{"id":"api_get-source-code","name":"repl\/get-source-code","signatures":["(get-source-code ns-str name-str)"],"desc":"Returns the source code of the definition identified by namespace and name\n  strings, or nil if the source file cannot be found or metadata is missing.","anchor":"repl-get-source-code","type":"api","kind":"function"},{"id":"api_get-symbol-info","name":"repl\/get-symbol-info","signatures":["(get-symbol-info ns-str name-str)"],"desc":"Returns a hash-map of structured metadata for the definition identified by\n  namespace and name strings. Returns nil if no such definition exists.\n\n  Keys: :doc, :file, :line, :column, :end-line, :end-column, :private,\n        :deprecated, :min-arity, :max-arity, :is-variadic, :ns, :name","anchor":"repl-get-symbol-info","type":"api","kind":"function"},{"id":"api_load-file","name":"repl\/load-file","signatures":["(load-file path)"],"desc":"Loads and evaluates a Phel source file in the current REPL session.\n  Reads the file content and evaluates it using the compiler, preserving\n  the current REPL namespace context. Returns the result of the last expression.","anchor":"repl-load-file","type":"api","kind":"function"},{"id":"api_loaded-namespaces","name":"repl\/loaded-namespaces","signatures":["(loaded-namespaces)"],"desc":"Returns all namespaces currently loaded in the REPL.","anchor":"repl-loaded-namespaces","type":"api","kind":"function"},{"id":"api_macroexpand","name":"repl\/macroexpand","signatures":["(macroexpand form)"],"desc":"Recursively expands the given form until it is no longer a macro call.\n  The form must be quoted to prevent evaluation, matching Clojure semantics.","anchor":"repl-macroexpand","type":"api","kind":"function"},{"id":"api_macroexpand-1","name":"repl\/macroexpand-1","signatures":["(macroexpand-1 form)"],"desc":"Expands the given form once if it is a macro call. The form must be\n  quoted to prevent evaluation, matching Clojure semantics.","anchor":"repl-macroexpand-1","type":"api","kind":"function"},{"id":"api_macroexpand-1-form","name":"repl\/macroexpand-1-form","signatures":["(macroexpand-1-form form)"],"desc":"Expands the given form once if it is a macro call.\n  Takes a quoted form and returns the expanded form, or the original\n  form unchanged if it is not a macro call. Uses the CompilerFacade\n  to perform the expansion without going through analyze+emit.","anchor":"repl-macroexpand-1-form","type":"api","kind":"function"},{"id":"api_macroexpand-form","name":"repl\/macroexpand-form","signatures":["(macroexpand-form form)"],"desc":"Recursively expands the given form until it is no longer a macro call.\n  Takes a quoted form and returns the fully expanded form. Uses the\n  CompilerFacade to perform the expansion without going through analyze+emit.","anchor":"repl-macroexpand-form","type":"api","kind":"function"},{"id":"api_ns-aliases","name":"repl\/ns-aliases","signatures":["(ns-aliases ns-str)"],"desc":"Returns a hash-map of {alias => namespace} for all require aliases in the\n  given namespace string.","anchor":"repl-ns-aliases","type":"api","kind":"function"},{"id":"api_ns-list","name":"repl\/ns-list","signatures":["(ns-list)"],"desc":"Returns a sorted vector of all loaded namespace names, decoded to\n  human-readable form (hyphens restored instead of underscores).","anchor":"repl-ns-list","type":"api","kind":"function"},{"id":"api_ns-publics","name":"repl\/ns-publics","signatures":["(ns-publics ns-str)"],"desc":"Returns a hash-map of {name => value} for all public definitions in the\n  given namespace string. Private definitions are excluded.","anchor":"repl-ns-publics","type":"api","kind":"function"},{"id":"api_ns-refers","name":"repl\/ns-refers","signatures":["(ns-refers ns-str)"],"desc":"Returns a hash-map of {name => source-namespace} for all referred symbols\n  in the given namespace string.","anchor":"repl-ns-refers","type":"api","kind":"function"},{"id":"api_print-colorful","name":"repl\/print-colorful","signatures":["(print-colorful & xs)"],"desc":"Prints arguments with colored output.","anchor":"repl-print-colorful","type":"api","kind":"function"},{"id":"api_println-colorful","name":"repl\/println-colorful","signatures":["(println-colorful & xs)"],"desc":"Prints arguments with colored output followed by a newline.","anchor":"repl-println-colorful","type":"api","kind":"function"},{"id":"api_require","name":"repl\/require","signatures":["(require sym & args)"],"desc":"Requires a Phel module into the environment.","anchor":"repl-require","type":"api","kind":"macro"},{"id":"api_search-doc","name":"repl\/search-doc","signatures":["(search-doc search)"],"desc":"Searches docstrings across all loaded namespaces for the given string.\n  Prints matching function names and their documentation.","anchor":"repl-search-doc","type":"api","kind":"function"},{"id":"api_source","name":"repl\/source","signatures":["(source sym)"],"desc":"Returns the source code of the given symbol as a string, or nil if unavailable.","anchor":"repl-source","type":"api","kind":"macro"},{"id":"api_symbol-info","name":"repl\/symbol-info","signatures":["(symbol-info sym)"],"desc":"Returns a hash-map of structured metadata for the given symbol, or nil if\n  the symbol cannot be resolved.\n\n  Keys: :doc, :file, :line, :column, :end-line, :end-column, :private,\n        :deprecated, :min-arity, :max-arity, :is-variadic, :ns, :name","anchor":"repl-symbol-info","type":"api","kind":"macro"},{"id":"api_test-ns","name":"repl\/test-ns","signatures":["(test-ns ns-str)"],"desc":"Runs all tests in a given namespace from the REPL.\n  Requires the namespace if not already loaded, finds all deftest definitions,\n  runs them, prints results, and returns a hash-map with :pass, :fail, and :error counts.\n  Preserves outer test state so it can be safely called during a test run.","anchor":"repl-test-ns","type":"api","kind":"function"},{"id":"api_use","name":"repl\/use","signatures":["(use sym & args)"],"desc":"Adds a use statement to the environment.","anchor":"repl-use","type":"api","kind":"macro"},{"id":"api_blank?","name":"str\/blank?","signatures":["(blank? s)"],"desc":"True if s is nil, empty, or contains only whitespace.","anchor":"str-blank","type":"api","kind":"function"},{"id":"api_capitalize","name":"str\/capitalize","signatures":["(capitalize s)"],"desc":"Converts first character to upper-case and all other characters to lower-case.","anchor":"str-capitalize","type":"api","kind":"function"},{"id":"api_chars","name":"str\/chars","signatures":["(chars s)"],"desc":"Returns a vector of characters from string s.\n\n  This is a convenience function for converting strings to character sequences.\n  Properly handles multibyte UTF-8 characters.","anchor":"str-chars","type":"api","kind":"function"},{"id":"api_contains?","name":"str\/contains?","signatures":["(contains? s substr)"],"desc":"True if s contains substr.","anchor":"contains-1","type":"api","kind":"function"},{"id":"api_ends-with?","name":"str\/ends-with?","signatures":["(ends-with? s substr)"],"desc":"True if s ends with substr.","anchor":"str-ends-with","type":"api","kind":"function"},{"id":"api_escape","name":"str\/escape","signatures":["(escape s cmap)"],"desc":"Returns a new string with each character escaped according to cmap.","anchor":"str-escape","type":"api","kind":"function"},{"id":"api_includes?","name":"str\/includes?","signatures":["(includes? s substr)"],"desc":"True if s includes substr.","anchor":"str-includes","type":"api","kind":"function"},{"id":"api_index-of","name":"str\/index-of","signatures":["(index-of s value & [from-index])"],"desc":"Returns the index of value in s, or nil if not found.","anchor":"str-index-of","type":"api","kind":"function"},{"id":"api_join","name":"str\/join","signatures":["(join separator & [coll])"],"desc":"Returns a string of all elements in coll, separated by an optional separator.","anchor":"str-join","type":"api","kind":"function"},{"id":"api_last-index-of","name":"str\/last-index-of","signatures":["(last-index-of s value & [from-index])"],"desc":"Returns the last index of value in s, or nil if not found.","anchor":"str-last-index-of","type":"api","kind":"function"},{"id":"api_lower-case","name":"str\/lower-case","signatures":["(lower-case s)"],"desc":"Converts string to all lower-case.","anchor":"str-lower-case","type":"api","kind":"function"},{"id":"api_pad-both","name":"str\/pad-both","signatures":["(pad-both s len & [pad-str])"],"desc":"Returns a string padded on both sides to length len.","anchor":"str-pad-both","type":"api","kind":"function"},{"id":"api_pad-left","name":"str\/pad-left","signatures":["(pad-left s len & [pad-str])"],"desc":"Returns a string padded on the left side to length len.","anchor":"str-pad-left","type":"api","kind":"function"},{"id":"api_pad-right","name":"str\/pad-right","signatures":["(pad-right s len & [pad-str])"],"desc":"Returns a string padded on the right side to length len.","anchor":"str-pad-right","type":"api","kind":"function"},{"id":"api_re-quote-replacement","name":"str\/re-quote-replacement","signatures":["(re-quote-replacement replacement)"],"desc":"Escapes special characters in a replacement string for literal use.","anchor":"str-re-quote-replacement","type":"api","kind":"function"},{"id":"api_repeat","name":"str\/repeat","signatures":["(repeat s n)"],"desc":"Returns a string containing n copies of s.","anchor":"str-repeat","type":"api","kind":"function"},{"id":"api_replace","name":"str\/replace","signatures":["(replace s match replacement)"],"desc":"Replaces all instances of match with replacement in s.","anchor":"str-replace","type":"api","kind":"function"},{"id":"api_replace-first","name":"str\/replace-first","signatures":["(replace-first s match replacement)"],"desc":"Replaces the first instance of match with replacement in s.","anchor":"str-replace-first","type":"api","kind":"function"},{"id":"api_reverse","name":"str\/reverse","signatures":["(reverse s)"],"desc":"Returns s with its characters reversed.","anchor":"str-reverse","type":"api","kind":"function"},{"id":"api_split","name":"str\/split","signatures":["(split s re & [limit])"],"desc":"Splits string on a regular expression, returning a vector of parts.","anchor":"str-split","type":"api","kind":"function"},{"id":"api_split-lines","name":"str\/split-lines","signatures":["(split-lines s)"],"desc":"Splits s on \\n or \\r\\n. Trailing empty lines are not returned.","anchor":"str-split-lines","type":"api","kind":"function"},{"id":"api_starts-with?","name":"str\/starts-with?","signatures":["(starts-with? s substr)"],"desc":"True if s starts with substr.","anchor":"str-starts-with","type":"api","kind":"function"},{"id":"api_subs","name":"str\/subs","signatures":["(subs s start & [end])"],"desc":"Returns the substring of s from start (inclusive) to end (exclusive).","anchor":"str-subs","type":"api","kind":"function"},{"id":"api_trim","name":"str\/trim","signatures":["(trim s)"],"desc":"Removes whitespace from both ends of string.","anchor":"str-trim","type":"api","kind":"function"},{"id":"api_trim-newline","name":"str\/trim-newline","signatures":["(trim-newline s)"],"desc":"Removes all trailing newline or return characters from string.","anchor":"str-trim-newline","type":"api","kind":"function"},{"id":"api_triml","name":"str\/triml","signatures":["(triml s)"],"desc":"Removes whitespace from the left side of string.","anchor":"str-triml","type":"api","kind":"function"},{"id":"api_trimr","name":"str\/trimr","signatures":["(trimr s)"],"desc":"Removes whitespace from the right side of string.","anchor":"str-trimr","type":"api","kind":"function"},{"id":"api_upper-case","name":"str\/upper-case","signatures":["(upper-case s)"],"desc":"Converts string to all upper-case.","anchor":"str-upper-case","type":"api","kind":"function"},{"id":"api_*testing-contexts*","name":"test\/*testing-contexts*","signatures":[],"desc":"Stack of testing context strings, most recent first.","anchor":"test-testing-contexts","type":"api","kind":"function"},{"id":"api_are","name":"test\/are","signatures":["(are argv expr & args)"],"desc":"Checks multiple assertions with a template expression.\n  `argv` is a vector of template variables, `expr` is the assertion template,\n  and the remaining `args` are partitioned by `(count argv)` to fill the template.\n  Template variables are substituted lexically at macro-expansion time, so\n  literal collection cells (e.g. `()`, `[]`, `{}`) are preserved as data and\n  are not evaluated as code.","anchor":"test-are","type":"api","kind":"macro"},{"id":"api_assert-expr","name":"test\/assert-expr","signatures":["(assert-expr & args)"],"desc":"","anchor":"test-assert-expr","type":"api","kind":"function"},{"id":"api_assert-expr-methods","name":"test\/assert-expr-methods","signatures":[],"desc":"","anchor":"test-assert-expr-methods","type":"api","kind":"function"},{"id":"api_deftest","name":"test\/deftest","signatures":["(deftest test-name & body)"],"desc":"Defines a test function.","anchor":"test-deftest","type":"api","kind":"macro"},{"id":"api_do-report","name":"test\/do-report","signatures":["(do-report m)"],"desc":"Add file and line information to a test result and call report.\n  If you are writing a custom assert-expr method, call this function\n  to pass test results to report.","anchor":"test-do-report","type":"api","kind":"function"},{"id":"api_get-stats","name":"test\/get-stats","signatures":["(get-stats)"],"desc":"Returns the current test statistics as a hash-map with :failed and :counts keys.","anchor":"test-get-stats","type":"api","kind":"function"},{"id":"api_is","name":"test\/is","signatures":["(is form & [message])"],"desc":"Asserts that an expression is true.","anchor":"test-is","type":"api","kind":"macro"},{"id":"api_print-summary","name":"test\/print-summary","signatures":["(print-summary)"],"desc":"Prints test results summary.","anchor":"test-print-summary","type":"api","kind":"function"},{"id":"api_report","name":"test\/report","signatures":["(report data)"],"desc":"Records test results and prints status indicators.","anchor":"test-report","type":"api","kind":"function"},{"id":"api_reset-stats","name":"test\/reset-stats","signatures":["(reset-stats)"],"desc":"Resets the test statistics to their initial state.\n  Call this before running a new batch of tests to get fresh results.","anchor":"test-reset-stats","type":"api","kind":"function"},{"id":"api_restore-stats","name":"test\/restore-stats","signatures":["(restore-stats saved)"],"desc":"Restores test statistics from a previously saved state.","anchor":"test-restore-stats","type":"api","kind":"function"},{"id":"api_run-tests","name":"test\/run-tests","signatures":["(run-tests options & namespaces)"],"desc":"Runs all tests in the given namespaces.","anchor":"test-run-tests","type":"api","kind":"function"},{"id":"api_successful?","name":"test\/successful?","signatures":["(successful?)"],"desc":"Checks if all tests passed.","anchor":"test-successful","type":"api","kind":"function"},{"id":"api_testing","name":"test\/testing","signatures":["(testing context & body)"],"desc":"Adds a testing context string. Used inside deftest to describe a group of assertions.\n  The context string is prepended to failure messages for better diagnostics.","anchor":"test-testing","type":"api","kind":"macro"},{"id":"doc_configuration","title":"Configuration","content":"<?php \/\/ phel-config.php return \\Phel\\Config\\PhelConfig::forProject('your-ns\\main'); <?php \/\/ phel-config.php return (new \\Phel\\Config\\PhelConfig()) ->setSrcDirs(['src']) ->setTestDirs(['tests']) ->se","url":"\/documentation\/configuration","type":"documentation"},{"id":"doc_getting-started","title":"Getting Started","content":"composer create-project --stability dev phel-lang\/cli-skeleton example-app cd example-app composer repl mkdir my-app && cd my-app composer require phel-lang\/phel-lang vendor\/bin\/phel init my-app vendo","url":"\/documentation\/getting-started","type":"documentation"},{"id":"doc_installation","title":"Installation","content":"composer create-project --stability dev phel-lang\/cli-skeleton example-app cd example-app composer repl composer require phel-lang\/phel-lang curl -L https:\/\/phel-lang.org\/phar -o phel.phar php phel.ph","url":"\/documentation\/installation","type":"documentation"},{"id":"doc_php-interop","title":"PHP Interop","content":"(get php\/$_SERVER \"key\") # Similar to $_SERVER['key'] (get php\/$GLOBALS \"argv\") # Similar to $GLOBALS['argv'] (php\/define \"MY_SETTING\" \"My value\") # Calls PHP define('MY_SETTING', 'My value\"); php\/MY_","url":"\/documentation\/php-interop","type":"documentation"},{"id":"doc_testing","title":"Testing","content":"\/\/ PHPUnit - class-based tests class MyTest extends TestCase { public function testAddition() { $this->assertEquals(4, 2 + 2); } } \/\/ Phel - function-based tests (deftest my-test (is (= 4 (+ 2 2)))) (","url":"\/documentation\/testing","type":"documentation"},{"id":"doc_why-phel","title":"Why Phel?","content":"# Call any PHP function (php\/strlen \"hello\") # => 5 (php\/array_map |(* $ 2) (php\/array 1 2 3)) # Create objects (php\/new \\DateTimeImmutable \"2024-01-15\") # Call methods (php\/-> date (format \"Y-m-d\")) ","url":"\/documentation\/why-phel","type":"documentation"}]